import {
    CollageElement,
    type PropertyDeclarations,
} from "collage/web-components/internal/CollageElement";
import template from "template!collage/clg-radio-circle";

/**
 * @tagname clg-radio-circle
 *
 * A radio circle display element.
 */
export class ClgRadioCircle extends CollageElement {
    protected static template = template;

    static properties: PropertyDeclarations = {
        checked: { type: Boolean, reflect: true },
        size: { type: String, reflect: true },
        backgroundType: {
            type: String,
            reflect: true,
            attribute: "background-type",
        },
        invalid: { type: Boolean, reflect: true },
    };

    /** Whether the radio is selected */
    declare checked: boolean;

    /** The size of the radio circle */
    declare size: "small" | "base";

    /** The style of background the radio circle is on */
    declare backgroundType: "dynamic" | "light" | "dark";

    /** Whether the radio circle is invalid */
    declare invalid: boolean;

    constructor() {
        super();
        this.backgroundType = "dynamic";
        this.size = "base";
        this.checked = false;
        this.invalid = false;
    }
}

ClgRadioCircle.define("clg-radio-circle");

declare global {
    interface HTMLElementTagNameMap {
        "clg-radio-circle": ClgRadioCircle;
    }
}
