import {
    CollageElement,
    type PropertyDeclarations,
    type Validators,
    required,
} from "collage/web-components/internal/CollageElement";
import template from "template!collage/clg-avatar-group";

/**
 * @tagname clg-avatar-group
 *
 * @slot shop - The `<clg-shop-avatar>` that shows the shop's image.
 * @slot profile - The `<clg-profile-avatar>` that shows the person associated with the shop.
 *
 */
export class ClgAvatarGroup extends CollageElement {
    protected static template = template;

    /**
     * Size variant for the shop avatar.
     * @required
     */
    declare size: "larger" | "largest";

    static override properties: PropertyDeclarations = {
        size: { type: String, reflect: true },
    };
    protected static validators: Validators = {
        size: required,
    };
}

ClgAvatarGroup.define("clg-avatar-group");

declare global {
    interface HTMLElementTagNameMap {
        "clg-avatar-group": ClgAvatarGroup;
    }
}
