import {
    nonDefaultStringConverter,
    type PropertyDeclarations,
} from "collage/web-components/internal/CollageElement";
import template from "template!collage/clg-brand-icon";
import { ClgBaseIcon } from "collage/web-components/internal/base-icon";
import type { BrandIconName } from "collage/web-components/internal/icons";

/**
 * @tagname clg-brand-icon
 */
export class ClgBrandIcon extends ClgBaseIcon {
    protected static override template = template;

    static override properties: PropertyDeclarations = {
        size: {
            type: String,
            reflect: true,
            converter: nonDefaultStringConverter("base"),
        },
        variant: {
            type: String,
            reflect: true,
            converter: nonDefaultStringConverter("base"),
        },
    };

    /**
     * Size of the icon
     */
    declare size: "smallest" | "smaller" | "base" | "larger" | "largest";

    /** The name of the icon to draw. */
    declare name: BrandIconName;

    declare variant:
        | "base"
        | "empty"
        | "success01"
        | "success02"
        | "error01"
        | "error02"
        | "marketing01"
        | "marketing02"
        | "marketing03";

    protected getIconUrl(name: string): string {
        return this.getBasePath(`brand/${name}.svg`);
    }

    protected get root() {
        return this.shadowRoot?.querySelector<HTMLElement>(".clg-brand-icon");
    }

    constructor() {
        super();
        this.size = "base";
        this.variant = "base";
    }
}

ClgBrandIcon.define("clg-brand-icon");

declare global {
    interface HTMLElementTagNameMap {
        "clg-brand-icon": ClgBrandIcon;
    }
}
