import type {
    ReactiveElement,
    ReactiveController,
    ReactiveControllerHost,
} from "@lit/reactive-element";
import { announce } from "common/a11y/A11yAnnouncer";
import { loadingMsg } from "collage/web-components/internal/translations";

type HostElement = ReactiveControllerHost &
    ReactiveElement & {
        loading?: boolean;
    };

export class LoadingButtonController implements ReactiveController {
    host: HostElement;
    getTarget: () => HTMLElement | null | undefined;
    #wasLoading = false;
    #isFocused = false;

    constructor(
        host: HostElement,
        getTarget: () => HTMLElement | null | undefined
    ) {
        (this.host = host).addController(this);
        this.getTarget = getTarget;
    }

    async hostConnected() {
        try {
            await this.host.updateComplete;
            const target = this.getTarget();
            target?.addEventListener("focus", this.#handleFocus);
            target?.addEventListener("blur", this.#handleBlur);
            target?.addEventListener("click", this.#handleClick);
            // eslint-disable-next-line @typescript-eslint/no-unused-vars
        } catch (e) {
            // If the host errors and we then try to await its `updateComplete`
            // it could throw again. We just want to quietly bail in that case.
        }
    }

    hostDisconnected() {
        const target = this.getTarget();
        target?.removeEventListener("focus", this.#handleFocus);
        target?.removeEventListener("blur", this.#handleBlur);
        target?.removeEventListener("click", this.#handleClick);
    }

    hostUpdated() {
        if (this.host.loading !== this.#wasLoading) {
            if (!this.#wasLoading && this.#isFocused && this.host.loading) {
                announce(loadingMsg, "assertive");
            }
            this.#wasLoading = Boolean(this.host.loading);
        }
    }

    #handleFocus = () => {
        this.#isFocused = true;
    };
    #handleBlur = () => {
        this.#isFocused = false;
    };
    #handleClick = (e: Event) => {
        if (this.host.loading) {
            e.preventDefault();
            e.stopImmediatePropagation();
        }
    };
}
