import {
    CollageElement,
    type PropertyDeclarations,
    type PropertyValues,
    nonDefaultStringConverter,
} from "collage/web-components/internal/CollageElement";
import template from "template!collage/clg-loading-spinner";
import { loadingMsg } from "collage/web-components/internal/translations";

/**
 * @tagname clg-loading-spinner
 */
export class ClgLoadingSpinner extends CollageElement {
    protected static template = template;

    /** Changes the presentation of the spinner to improve contrast against the specified background. */
    declare backgroundType: "dynamic" | "light" | "dark";
    /** The size of the loading spinner. */
    declare size: "base" | "large";
    /** A visually hidden, but screen-reader accessible label for the loading spinner. */
    declare label: string;

    static override properties: PropertyDeclarations = {
        backgroundType: {
            type: String,
            reflect: true,
            attribute: "background-type",
        },
        size: {
            type: String,
            reflect: true,
            converter: nonDefaultStringConverter("base"),
        },
        label: {},
    };

    constructor() {
        super();
        this.backgroundType = "dynamic";
        this.size = "base";
        this.label = loadingMsg;
    }

    willUpdate(changed: PropertyValues) {
        super.willUpdate(changed);

        // Ensure there's always a label, unless explicitly nullified
        this.label = this.label || loadingMsg;
    }
}

ClgLoadingSpinner.define("clg-loading-spinner");

declare global {
    interface HTMLElementTagNameMap {
        "clg-loading-spinner": ClgLoadingSpinner;
    }
}
