import {
    CollageElement,
    type PropertyDeclarations,
    type Validators,
} from "collage/web-components/internal/CollageElement";
import template from "template!collage/clg-global-alert-banner";
import "collage/web-components/components/banner/clg-banner-base";
import "collage/web-components/components/icon/clg-icon";

/**
 * @tagname clg-global-alert-banner
 *
 * @dependency clg-banner-base
 * @dependency clg-icon
 *
 * @slot - banner message
 * @slot icon - icon
 * @slot title - banner title
 *
 * @fires {ClgCloseEvent} clg-close - Event fired when the close button is clicked.
 */
export class ClgGlobalAlertBanner extends CollageElement {
    protected static template = template;

    /**
     * Color variants based on the purpose of the message.
     * @required
     */
    declare color: "warning" | "critical";
    /**
     * Buttons variants for different call to action use cases.
     */
    declare buttons?: "buttonGroup" | "inlineButton" | "dismissOnly" | "none";
    /**
     * Buttons variants for different call to action use cases.
     */
    declare open?: boolean;

    static override properties: PropertyDeclarations = {
        color: { type: String, reflect: true },
        buttons: { type: String, reflect: true },
        open: { type: Boolean, reflect: true },
    };

    protected static validators: Validators = {
        color: {
            property(value, context) {
                if (value !== "warning" && value !== "critical") {
                    return `${context.tagName}: color must be 'warning' or 'critical'`;
                }
                return null;
            },
        },
    };

    constructor() {
        super();
        this.buttons = "none";
        this.open = false;
    }
}

ClgGlobalAlertBanner.define("clg-global-alert-banner");

declare global {
    interface HTMLElementTagNameMap {
        "clg-global-alert-banner": ClgGlobalAlertBanner;
    }
}
