import {
    CollageElement,
    type PropertyDeclarations,
    type PropertyValues,
} from "collage/web-components/internal/CollageElement";
import template from "template!collage/clg-image-tile";

/**
 * @tagname clg-image-tile
 *
 * @summary A component that displays a one or more images in a specific layout (row, grid, mosaic).
 * @slot - This holds clg-on-image components, WtImage components, or plain img elements. These are used to display content on top of the image.
 * @example
 * <clg-image-tile layout="one-one">
 *     <clg-on-image>
 *         <clg-signal color="trust" variant="strong" size="base">Etsy's Pick</clg-signal>
 *         <img src="https://placehold.co/300x300/png" alt="Fallback Image" style="width: 100%; height: 100%; object-fit: cover;" />
 *     </clg-on-image>
 * </clg-image-tile>
 * @example
 * <clg-image-tile layout="one-one-row">
 *     <clg-on-image>
 *         <clg-signal color="trust" variant="strong" size="base">Etsy's Pick</clg-signal>
 *         <img src="https://placehold.co/300x300/png" alt="Fallback Image" />
 *     </clg-on-image>
 *     <clg-on-image>
 *         <clg-signal color="trust" variant="strong" size="base">Etsy's Pick</clg-signal>
 *         <img src="https://placehold.co/300x300/png" alt="Fallback Image" />
 *     </clg-on-image>
 * </clg-image-tile>
 *
 */
export class ClgImageTile extends CollageElement {
    protected static override template = template;

    static override properties: PropertyDeclarations = {
        layout: { type: String, reflect: true },
        rounded: { type: Boolean, reflect: true },
        placeholders: {
            type: Number,
            reflect: true,
        },
    };

    /** Layout of the image tile */
    declare layout:
        | "one-one"
        | "one-one-row"
        | "one-one-grid"
        | "one-one-mosaic-vertical"
        | "one-one-mosaic-horizontal"
        | "four-five"
        | "four-five-row"
        | "four-five-grid"
        | "four-five-mosaic-horizontal"
        | "five-four"
        | "five-four-row"
        | "five-four-grid"
        | "five-four-mosaic-vertical";

    /** Whether the image tile has rounded corners */
    declare rounded: boolean;

    /**
     * Number of placeholders visible. This only applies to "grid" layouts, and the max is 3.
     * This should only be manually set on the server side to control the initial render.
     * It will be automatically updated in the browser based on the number of images present.
     */
    declare placeholders: number;

    #observer: MutationObserver | null = null;

    willUpdate(changed: PropertyValues) {
        super.willUpdate(changed);

        if (changed.has("layout")) {
            this.#checkForPlaceholder();
            this.#setupObserver();
        }
    }

    disconnectedCallback() {
        super.disconnectedCallback();
        this.#cleanupObserver();
    }

    #setupObserver() {
        if (!this.layout.includes("grid")) {
            this.#cleanupObserver();
            return;
        }

        if (this.#observer) return;

        this.#observer = new MutationObserver(() => {
            this.updateComplete.then(() => this.#checkForPlaceholder());
        });
        this.#observer.observe(this, { childList: true });
    }

    #cleanupObserver() {
        this.#observer?.disconnect();
        this.#observer = null;
    }

    #checkForPlaceholder() {
        if (!this.layout.includes("grid")) return;
        this.placeholders = 4 - this.children.length;
    }

    constructor() {
        super();
        this.layout = "one-one";
        this.rounded = false;
        this.placeholders = 0;
    }
}

ClgImageTile.define("clg-image-tile");

declare global {
    interface HTMLElementTagNameMap {
        "clg-image-tile": ClgImageTile;
    }
}
