import {
    autoUpdate,
    computePosition,
    flip,
    getOverflowAncestors,
    offset,
    platform,
    shift,
    size,
    type Placement,
    type ReferenceElement,
} from "@floating-ui/dom";
import {
    CollageElement,
    type PropertyDeclarations,
    type PropertyValues,
} from "collage/web-components/internal/CollageElement";
import { composedOffsetParentPolyfill } from "collage/web-components/internal/composed-offset-parent";
import { ClgRepositionEvent } from "collage/web-components/events/reposition";
import template from "template!collage/clg-floating-element";

/** @public Virtual anchor (e.g. selection rect) for Floating UI. */
export interface ClgFloatingVirtualAnchor {
    getBoundingClientRect: () => DOMRect;
    contextElement?: Element;
}

function isVirtualAnchor(value: unknown): value is ClgFloatingVirtualAnchor {
    if (value === null || typeof value !== "object" || value instanceof Element) {
        return false;
    }
    if (!("getBoundingClientRect" in value)) {
        return false;
    }
    return typeof value.getBoundingClientRect === "function";
}

const SUPPORTS_POPOVER =
    typeof HTMLElement !== "undefined" &&
    Object.prototype.hasOwnProperty.call(HTMLElement.prototype, "popover");

export type ClgFloatingElementPlacement = Placement;

export type ClgFloatingBoundaryMode = "viewport" | "scroll";

export type ClgFloatingAutoSize = "horizontal" | "vertical" | "both";

/**
 * @tagname clg-floating-element
 * @summary Anchors a floating element to another element using Floating UI.
 *   When `active` is true the panel is positioned and shown; when false it is hidden.
 *   With Popover API support the panel is promoted to the top layer and positioned
 *   absolutely using a composed offset parent polyfill. Without Popover API,
 *   `position: fixed` is used to escape stacking contexts.
 *
 * @slot anchor - The element to anchor the panel to. If not used, set the `anchor` property to an id string or element reference.
 * @slot - The floating element content.
 *
 * @fires {ClgRepositionEvent} clg-reposition - Fired after the panel position is recomputed (may fire often; debounce heavy work).
 *
 * @example
 * ```html
 * <clg-floating-element id="tip" anchor="trigger-btn" active placement="bottom">
 *   <span>Tooltip content</span>
 * </clg-floating-element>
 * ```
 */
export class ClgFloatingElement extends CollageElement {
    protected static override template = template;

    static override properties: PropertyDeclarations = {
        active: { type: Boolean, reflect: true },
        placement: { type: String, reflect: true },
        anchor: {
            type: Object,
            converter: {
                fromAttribute: (value: string | null) => value ?? undefined,
                toAttribute: (
                    value:
                        | string
                        | HTMLElement
                        | ClgFloatingVirtualAnchor
                        | null
                        | undefined
                ) => (typeof value === "string" ? value : undefined),
            },
        },
        distance: { type: Number, reflect: true },
        skidding: { type: Number, reflect: true },
        flip: { type: Boolean, reflect: true },
        flipPadding: { type: Number, reflect: true, attribute: "flip-padding" },
        shift: { type: Boolean, reflect: true },
        shiftPadding: {
            type: Number,
            reflect: true,
            attribute: "shift-padding",
        },
        boundary: { type: String, reflect: true },
        matchAnchorWidth: {
            type: Boolean,
            reflect: true,
            attribute: "match-anchor-width",
        },
        autoSize: {
            type: String,
            reflect: true,
            attribute: "auto-size",
        },
        popupRole: {
            type: String,
            reflect: true,
            attribute: "popup-role",
        },
    };

    /** When true, the panel is positioned and visible; when false, it is hidden. */
    declare active: boolean;
    /** Preferred placement of the panel relative to the anchor. */
    declare placement: ClgFloatingElementPlacement;
    /**
     * Anchor: element id, HTMLElement reference, or virtual anchor.
     * Allows anchoring to a specific element that's not in the anchor slot.
     * If unset, whatever is in the `anchor` slot is used.
     */
    declare anchor?: string | HTMLElement | ClgFloatingVirtualAnchor | null;

    /** Distance in pixels from the anchor (main axis). */
    declare distance: number;

    /** Skidding in pixels along the anchor (cross axis). */
    declare skidding: number;

    /** When true, flip placement to keep the panel in view. */
    declare flip: boolean;

    /** Padding in pixels before flip occurs. */
    declare flipPadding: number;

    /** When true, shift the panel along the axis to keep it in view when clipped. */
    declare shift: boolean;

    /** Padding in pixels before shift occurs. */
    declare shiftPadding: number;

    /**
     * Overflow boundary for flip/shift/size when using Popover API.
     * `scroll` uses the anchor's overflow ancestors (Popover moves the popup out of that tree).
     */
    declare boundary: ClgFloatingBoundaryMode;

    /** When true, the popup width matches the anchor width (combobox / menus). */
    declare matchAnchorWidth: boolean;

    /**
     * Resize to stay within the viewport on an axis: `horizontal`, `vertical`, or `both`.
     * Exposes `--clg-floating-auto-size-available-width` / `-height` on the host.
     */
    declare autoSize?: ClgFloatingAutoSize;

    /** ARIA role for the popup (e.g. `tooltip`, `dialog`, `listbox`). Omit for no role. */
    declare popupRole?: string;

    #cleanup: (() => void) | undefined;
    #referenceEl: ReferenceElement | null = null;

    #onAnchorSlotChange = (): void => {
        if (this.anchor === undefined || this.anchor === null) {
            this.#handleAnchorChange();
        }
    };

    constructor() {
        super();
        this.active = false;
        this.placement = "bottom";
        this.distance = 8;
        this.skidding = 0;
        this.flip = true;
        this.flipPadding = 5;
        this.shift = true;
        this.shiftPadding = 5;
        this.boundary = "viewport";
        this.matchAnchorWidth = false;
    }

    get #popupEl(): HTMLElement | null {
        return (
            this.shadowRoot?.querySelector<HTMLElement>(
                ".clg-floating-element__popup"
            ) ?? null
        );
    }

    #resolveReference(): ReferenceElement | null {
        if (this.anchor === undefined || this.anchor === null) {
            const slot =
                this.shadowRoot?.querySelector<HTMLSlotElement>(
                    'slot[name="anchor"]'
                );
            if (!slot) {
                return null;
            }
            let node = slot.assignedElements({ flatten: true })[0];
            if (node instanceof HTMLSlotElement) {
                node = node.assignedElements({ flatten: true })[0];
            }
            return node instanceof HTMLElement ? node : null;
        }
        if (typeof this.anchor === "string") {
            const root = this.getRootNode();
            if (
                !(
                    "getElementById" in root &&
                    typeof root.getElementById === "function"
                )
            ) {
                return null;
            }
            const el = root.getElementById(this.anchor);
            return el instanceof HTMLElement ? el : null;
        }
        if (this.anchor instanceof HTMLElement) {
            return this.anchor;
        }
        if (isVirtualAnchor(this.anchor)) {
            return this.anchor;
        }
        return null;
    }

    #getPlatform() {
        const getOffsetParent = SUPPORTS_POPOVER
            ? (element: Element) =>
                  platform.getOffsetParent(element, composedOffsetParentPolyfill)
            : platform.getOffsetParent;
        return {
            ...platform,
            getOffsetParent,
        };
    }

    /**
     * Repositions the floating element.
     * This is the main function that is called when the anchor or viewport changes.
     * It is responsible for positioning the floating element and ensuring that it is visible.
     * It is also responsible for ensuring that the floating element is within the viewport and not clipped by the anchor.
     * https://github.com/shoelace-style/webawesome/blob/67bdccc4c39b22d2203021a6e9c4c00f662119e6/packages/webawesome/src/components/popup/popup.ts#L320
     */
    #reposition = (): void => {
        const referenceEl = this.#referenceEl;
        const popup = this.#popupEl;
        if (!referenceEl || !popup || !this.active) return;

        const middleware = [
            offset({ mainAxis: this.distance, crossAxis: this.skidding }),
        ];

        if (this.matchAnchorWidth) {
            middleware.push(
                size({
                    apply: ({ rects }) => {
                        Object.assign(popup.style, {
                            width: `${rects.reference.width}px`,
                        });
                    },
                })
            );
        } else {
            popup.style.width = "";
        }

        let defaultBoundary: Element[] | undefined;
        if (
            SUPPORTS_POPOVER &&
            this.boundary === "scroll" &&
            referenceEl instanceof Element
        ) {
            defaultBoundary = getOverflowAncestors(referenceEl).filter(
                (node): node is Element => node instanceof Element
            );
        }

        if (this.flip) {
            middleware.push(
                flip({
                    boundary: defaultBoundary,
                    padding: this.flipPadding,
                })
            );
        }
        if (this.shift) {
            middleware.push(
                shift({
                    boundary: defaultBoundary,
                    padding: this.shiftPadding,
                })
            );
        }

        const autoSize = this.autoSize;
        if (
            autoSize === "horizontal" ||
            autoSize === "vertical" ||
            autoSize === "both"
        ) {
            middleware.push(
                size({
                    boundary: defaultBoundary,
                    apply: ({ availableWidth, availableHeight }) => {
                        if (autoSize === "vertical" || autoSize === "both") {
                            this.style.setProperty(
                                "--clg-floating-auto-size-available-height",
                                `${availableHeight}px`
                            );
                        } else {
                            this.style.removeProperty(
                                "--clg-floating-auto-size-available-height"
                            );
                        }
                        if (autoSize === "horizontal" || autoSize === "both") {
                            this.style.setProperty(
                                "--clg-floating-auto-size-available-width",
                                `${availableWidth}px`
                            );
                        } else {
                            this.style.removeProperty(
                                "--clg-floating-auto-size-available-width"
                            );
                        }
                    },
                })
            );
        } else {
            this.style.removeProperty("--clg-floating-auto-size-available-width");
            this.style.removeProperty("--clg-floating-auto-size-available-height");
        }

        const strategy = SUPPORTS_POPOVER ? "absolute" : "fixed";

        computePosition(referenceEl, popup, {
            placement: this.placement,
            middleware,
            strategy,
            platform: this.#getPlatform(),
        }).then(({ x, y, placement }) => {
            this.setAttribute("data-current-placement", placement);
            Object.assign(popup.style, {
                left: `${x}px`,
                top: `${y}px`,
            });
            this.dispatchEvent(new ClgRepositionEvent({ placement }));
        });
    };

    #syncPopupLayoutClass(popup: HTMLElement): void {
        popup.classList.toggle(
            "clg-floating-element__popup--fixed",
            !SUPPORTS_POPOVER
        );
    }

    #syncPopupRole(popup: HTMLElement): void {
        const role = this.popupRole;
        if (role && role.length > 0) {
            popup.setAttribute("role", role);
        } else {
            popup.removeAttribute("role");
        }
    }

    #showPopupLayer(): void {
        const layer = this.#popupEl;
        if (!layer) {
            return;
        }
        layer.hidden = false;
        layer.setAttribute("aria-hidden", "false");
        if (SUPPORTS_POPOVER) {
            try {
                layer.showPopover?.();
            } catch {
                // Invalid state (e.g. already open) — continue with positioning
            }
        }
    }

    #hidePopupLayer(): void {
        const layer = this.#popupEl;
        if (!layer) {
            return;
        }
        if (SUPPORTS_POPOVER) {
            try {
                layer.hidePopover?.();
            } catch {
                // Already hidden
            }
        }
        layer.hidden = true;
        layer.setAttribute("aria-hidden", "true");
    }

    #start(): void {
        const referenceEl = this.#resolveReference();
        const popup = this.#popupEl;
        if (!referenceEl || !popup || !this.active || !this.isConnected) return;

        this.#referenceEl = referenceEl;
        this.#syncPopupLayoutClass(popup);
        this.#syncPopupRole(popup);
        this.#showPopupLayer();

        this.#cleanup = autoUpdate(referenceEl, popup, this.#reposition);
    }

    #stop(): void {
        if (this.#cleanup) {
            this.#cleanup();
            this.#cleanup = undefined;
        }
        this.#referenceEl = null;
        this.removeAttribute("data-current-placement");
        this.style.removeProperty("--clg-floating-auto-size-available-width");
        this.style.removeProperty("--clg-floating-auto-size-available-height");
        const popup = this.#popupEl;
        if (popup) {
            this.#hidePopupLayer();
            popup.style.width = "";
        }
    }

    /** Stop, then start if active (resolves anchor and runs positioner). */
    #handleAnchorChange(): void {
        this.#stop();
        if (this.active) {
            this.#start();
        }
    }

    #attachAnchorSlotListener(): void {
        const slot =
            this.shadowRoot?.querySelector<HTMLSlotElement>('slot[name="anchor"]');
        slot?.addEventListener("slotchange", this.#onAnchorSlotChange);
    }

    #detachAnchorSlotListener(): void {
        const slot =
            this.shadowRoot?.querySelector<HTMLSlotElement>('slot[name="anchor"]');
        slot?.removeEventListener("slotchange", this.#onAnchorSlotChange);
    }

    override connectedCallback(): void {
        super.connectedCallback();
        this.updateComplete.then(() => {
            this.#attachAnchorSlotListener();
            const popup = this.#popupEl;
            if (popup) {
                this.#syncPopupLayoutClass(popup);
                this.#syncPopupRole(popup);
            }
            if (this.active) {
                this.#handleAnchorChange();
            }
        });
    }

    override disconnectedCallback(): void {
        this.#detachAnchorSlotListener();
        this.#stop();
        super.disconnectedCallback();
    }

    override update(changed: PropertyValues): void {
        super.update(changed);

        const popup = this.#popupEl;
        if (popup && changed.has("popupRole")) {
            this.#syncPopupRole(popup);
        }

        if (changed.has("active")) {
            if (this.active) {
                this.#handleAnchorChange();
            } else {
                this.#stop();
            }
            return;
        }
        if (changed.has("anchor")) {
            this.#handleAnchorChange();
            return;
        }
        if (
            this.active &&
            (changed.has("placement") ||
                changed.has("distance") ||
                changed.has("skidding") ||
                changed.has("flip") ||
                changed.has("flipPadding") ||
                changed.has("shift") ||
                changed.has("shiftPadding") ||
                changed.has("boundary") ||
                changed.has("matchAnchorWidth") ||
                changed.has("autoSize"))
        ) {
            this.#reposition();
        }
    }

    /** Recalculates and repositions the panel. Call when anchor or viewport changes. */
    reposition(): void {
        this.#reposition();
    }
}

ClgFloatingElement.define("clg-floating-element");

declare global {
    interface HTMLElementTagNameMap {
        "clg-floating-element": ClgFloatingElement;
    }
}
