import {
    CollageElement,
    type PropertyDeclarations,
    type Validators,
    type ValidatorConfig,
    type ValidatorContext,
    type PropertyValidator,
    type SlotValidator,
    type PropertyValues,
    nonEmptyStringConverter,
    required,
    hasContent,
    DEFAULT_SLOT,
} from "collage/web-components/internal/CollageElement";

export {
    type Validators,
    type ValidatorConfig,
    type ValidatorContext,
    type PropertyValidator,
    type SlotValidator,
    type PropertyDeclarations,
    type PropertyValues,
    required,
    hasContent,
    DEFAULT_SLOT,
};

export interface ValidityResult {
    flags: Partial<Omit<ValidityState, "valid">>;
    message?: string;
    anchor?: HTMLElement;
}

export abstract class CollageFormElement extends CollageElement {
    static readonly formAssociated = true;

    protected internals: ElementInternals;

    /** Sets whether the control is usable and clickable */
    declare disabled: boolean;

    /**
     * Whether the form control is showing an error state to the user. The input value
     * can still be invalid if this property is false. To check whether the form control
     * is valid, use `checkValidity()`.
     */
    protected declare invalid: boolean;

    /** Gets the form control's current validation message or an empty string when the form control is valid. */
    protected declare validationMessage: string;

    /**
     * The error message to display. Setting this property will cause the form control to also
     * present an error/invalid state. To hide the error message and show the user the valid state,
     * set this to an empty string ('').
     *
     * If set, it will override the validity state of the Contraint Validation API. To show a custom
     * error message while using the Contraint Validation API, use the `setCustomValidity()` method instead.
     */
    declare error: string;

    /**
     * A string specifying a name for the input control. This name is
     * submitted along with the control's value when the form data is submitted.
     */
    declare name: string;

    /** Accessible label of the input */
    declare label: string;
    /** Additional context or explanation displayed beneath the form field */
    declare caption: string;
    /** Additional context or instructions for the form field */
    declare helperText: string;
    /** For SSR support with slots, sets whether the caption slot is occupied */
    declare withCaption?: boolean;
    /** For SSR support with slots, sets whether the helper-text slot is occupied */
    declare withHelperText: boolean;
    /** Visually hide the label, but still show it to assistive technologies like screen readers. */
    declare hideLabel: boolean;
    /** Visually hide the helper text, but still show it to assistive technologies like screen readers. */
    declare hideHelperText: boolean;

    static override properties: PropertyDeclarations = {
        disabled: { type: Boolean, reflect: true },
        error: { type: String },
        name: { type: String, reflect: true, converter: nonEmptyStringConverter },
        validationMessage: { type: String, state: true },
        invalid: { type: Boolean, reflect: true, attribute: "invalid" },
        label: { type: String },
        caption: { type: String },
        helperText: { type: String, attribute: "helper-text" },
        withCaption: {
            type: Boolean,
            reflect: true,
            attribute: "with-caption",
        },
        withHelperText: {
            type: Boolean,
            reflect: true,
            attribute: "with-helper-text",
        },
        hideLabel: { type: Boolean, attribute: "hide-label", reflect: true },
        hideHelperText: {
            type: Boolean,
            attribute: "hide-helper-text",
            reflect: true,
        },
    };

    constructor() {
        super();
        this.internals = this.attachInternals();

        this.helperText = "";
        this.caption = "";
        this.disabled = false;
        this.error = "";
        this.invalid = false;
        this.validationMessage = "";
        this.name = "";
        this.withCaption = false;
        this.withHelperText = false;
        this.hideLabel = false;
        this.hideHelperText = false;
    }

    /** Flag tracking whether the user has interacted with the form element */
    protected touched = false;

    /**
     * Flag to track whether `checkValidity()` is being called.
     * `checkValidity()` automatically fires the `invalid` event, which
     * can cause our custom error display to show, since the `invalid`
     * event also fires when a form submits. The purpose of `checkValidity()`
     * is to be able to "silently" check the validity state, so we use this flag
     * to make sure we don't show the error state when `checkValidity()` is called.
     */
    #checkingValidity = false;

    protected override willUpdate(changed: PropertyValues) {
        super.willUpdate(changed);

        if (this.error && this.error.length > 0) {
            this.invalid = true;
            this.validationMessage = this.error;
        }

        if (!this.hasSlotContent("helper-text")) {
            this.withHelperText = Boolean(
                this.helperText && this.helperText.length > 0
            );
        }

        if (!this.hasSlotContent("caption")) {
            this.withCaption = Boolean(this.caption && this.caption.length > 0);
        }
    }

    connectedCallback() {
        super.connectedCallback();

        const handleSlotChange = (e: Event) => {
            const target = e.target;
            if (!(target instanceof HTMLSlotElement)) return;
            if (target.name === "helper-text") {
                this.withHelperText = this.hasSlotContent("helper-text");
            }
            if (target.name === "caption") {
                this.withCaption = this.hasSlotContent("caption");
            }
        };

        this.shadowRoot?.addEventListener("slotchange", handleSlotChange);

        const handleInvalidEvent = (e: Event) => {
            if (!this.#checkingValidity) {
                this.invalid = true;
                this.touched = true;
            }

            // Use to prevent showing browser tooltip
            // Also prevents focusing the input, so we'll need to handle that too
            e.preventDefault();

            this.#checkingValidity = false;
        };

        // eslint-disable-next-line wc/require-listener-teardown
        this.addEventListener("invalid", handleInvalidEvent);

        this.onDisconnect(() => {
            this.removeEventListener("invalid", handleInvalidEvent);
            this.shadowRoot?.removeEventListener("slotchange", handleSlotChange);
        });
    }

    /**
     * Syncs the form control's validity with the internal input's validity.
     * Subclasses MUST call this whenever the value property changes.
     *
     * @example
     * ```ts
     * updated(changed: PropertyValues) {
     *     if (changed.has('value')) {
     *         this.updateValidity()
     *     }
     * }
     * ```
     */
    protected abstract getValidity(): ValidityResult;

    protected validate() {
        const { flags, message, anchor } = this.getValidity();
        this.internals.setValidity(flags, message, anchor);
        return this.checkValidity();
    }

    /** The value set via `setCustomValidity`. */
    protected customValidityMessage = "";

    /** The current validity state of the control. */
    public get validity() {
        return this.internals.validity;
    }

    /** Returns true if the control will be validated when its form is submitted. */
    public get willValidate() {
        return this.internals.willValidate;
    }

    /**
     * Checks if the form control has any restraints and whether it satisfies
     * them. If invalid, `false` will be returned and the `invalid` event will
     * be dispatched. If valid, `true` will be returned.
     */
    public checkValidity() {
        this.#checkingValidity = true;
        return this.internals.checkValidity();
    }

    /** Returns the form owner of this element */
    public get form() {
        return this.internals.form;
    }

    /**
     * Sets a custom validation message for the form control. If this message
     * is not an empty string, then the form control is considered invalid and
     * the specified message will be displayed to the user when reporting
     * validity. Setting an empty string clears the custom validity state.
     */
    public setCustomValidity(message: string) {
        this.customValidityMessage = message;
        this.internals.setValidity({ customError: message !== "" }, message);
        this.getValidity();
    }

    /**
     * Returns the current custom validation message or an empty string if no
     * custom error is set.
     */
    protected getCustomValidity(): string {
        return this.internals.validity.customError
            ? this.internals.validationMessage
            : "";
    }

    /**
     * Checks if the form control has any restraints and whether it satisfies
     * them. If invalid, `false` will be returned and the `invalid` event will
     * be dispatched. In addition, the problem will be reported to the user.
     * If valid, `true` will be returned.
     */
    public reportValidity() {
        return this.internals.reportValidity();
    }

    /** Called when the form is reset. */
    protected formResetCallback(): void {
        this.invalid = false;
        this.touched = false;
    }

    /** Called when a containing <fieldset> is disabled. */
    protected formDisabledCallback(isDisabled: boolean): void {
        if (this.disabled !== isDisabled) {
            this.disabled = isDisabled;
        }
    }

    /** Called when the element is associated with a form. */
    protected formAssociatedCallback(_form: HTMLFormElement): void {
        // noop
    }

    /**
     * Called when the browser is trying to restore element’s state to state
     * in which case reason is “restore”, or when the browser is trying to
     * fulfill autofill on behalf of user in which case reason is “autocomplete”.
     * In the case of “restore”, state is a string, File, or FormData object
     * previously set as the second argument to `setFormValue`.
     * @internal
     */
    protected formStateRestoreCallback(
        /**
         * The value previously set as the second argument to `setFormValue`.
         */
        _state: string | File | FormData,
        /**
         * The cause for this callback being fired. It can be caused by:
         *
         * - **`restore`**: When the browser is trying to update the value on
         *   behalf of the user, like following a reload or page navigation.
         *
         * - **`autocomplete`**: When the browser is trying to autofill the value.
         */
        _reason: "restore" | "autocomplete"
    ): void {
        // noop
    }
}
