import {
    CollageElement,
    type PropertyDeclarations,
    type Validators,
    required,
} from "collage/web-components/internal/CollageElement";
import { announce } from "common/a11y/A11yAnnouncer";
import template from "template!collage/clg-removable-chip-group";
import { ClgChipRemoveEvent } from "collage/web-components/events/chip-remove";
import type { ClgRemovableChip } from "collage/web-components/components/chip/clg-removable-chip";
import { chipRemovedAnnouncementMsg } from "collage/web-components/internal/translations";

/**
 * @tagname clg-removable-chip-group
 * @slot - one or more clg-removable-chip

 * @fires {ClgChipRemoveEvent} clg-chip-remove - Event fired when a chip in the group is clicked
 *
 */
export class ClgRemovableChipGroup extends CollageElement {
    protected static override template = template;

    static override properties: PropertyDeclarations = {
        label: { type: String, reflect: true },
    };

    protected static validators: Validators = {
        label: required,
    };

    /**
     * The (screen reader only) aria label of the removable chip group
     * @required
     */
    declare label: string;

    static delegatedEvents = ["click"];

    /** @internal */
    handleEvent(event: Event) {
        if (event.type === "click") {
            const eventTarget = event.target;
            if (!(eventTarget instanceof HTMLElement)) {
                return;
            }
            const chip = eventTarget.closest("clg-removable-chip");
            if (!chip || chip.disabled) {
                return;
            }
            const defaultPrevented = !this.dispatchEvent(
                new ClgChipRemoveEvent({ chip })
            );
            if (defaultPrevented) {
                return;
            }
            this.removeChip(chip);
        }
    }

    removeChip(chip: ClgRemovableChip) {
        this.announceChipRemoval(chip);
        chip.remove();
    }

    announceChipRemoval(removableChipEl: ClgRemovableChip) {
        const label = removableChipEl.getAttribute("label");
        if (label) {
            announce(chipRemovedAnnouncementMsg({ label }), "polite");
        }
    }
}

ClgRemovableChipGroup.define("clg-removable-chip-group");

declare global {
    interface HTMLElementTagNameMap {
        "clg-removable-chip-group": ClgRemovableChipGroup;
    }
}
