import {
    CollageElement,
    type PropertyDeclarations,
    type Validators,
    required,
    hasContent,
    type PropertyValues,
} from "collage/web-components/internal/CollageElement";
import template from "template!collage/clg-radio";
import "collage/web-components/components/radio/clg-radio-circle";

/**
 * @tagname clg-radio
 *
 * @summary A form-associated radio control.
 *
 * @dependency clg-radio-circle
 *
 * @slot helper-text - The helper text for the radio
 * @slot - The label text, can be used instead of the `label` property.
 */
export class ClgRadio extends CollageElement {
    protected static template = template;

    static override properties: PropertyDeclarations = {
        label: { type: String, reflect: true },
        variant: { type: String, reflect: true },
        name: { type: String, reflect: true },
        value: { type: String, reflect: true },
        checked: { type: Boolean, reflect: true },
        disabled: { type: Boolean, reflect: true },
        invalid: { type: Boolean, reflect: true },
        helperText: { type: String, reflect: true, attribute: "helper-text" },
        withHelperText: {
            type: Boolean,
            reflect: true,
            attribute: "with-helper-text",
        },
        size: { type: String, reflect: true },
        backgroundType: {
            type: String,
            reflect: true,
            attribute: "background-type",
        },
    };

    protected static validators: Validators<ClgRadio> = {
        label: {
            property(this, value, context) {
                if (!this.shadowRoot) return;
                const slot =
                    this.shadowRoot.querySelector<HTMLSlotElement>(
                        "slot:not([name])"
                    );
                const missingSlot = hasContent.call(this, slot, {
                    tagName: "clg-radio",
                    key: "[default]",
                });
                if (!missingSlot) return;

                return required.call(this, value, context);
            },
        },
        "[default]": {
            slot(this, slot, context) {
                const missingLabel = required.call(this, this.label, {
                    tagName: "clg-radio",
                    key: "label",
                });
                if (!missingLabel) return;
                return hasContent.call(this, slot, context);
            },
        },
        value: required,
    };

    static delegatedEvents = ["slotchange"];

    /** Accessible label for the radio */
    declare label: string;

    /** Visual style variant, default is subtle */
    declare variant: "subtle" | "strong";

    /** Shared name for the radio */
    declare name?: string;

    /**
     * Value of the radio
     * @required
     */
    declare value: string;

    /** Whether the radio is checked */
    declare checked: boolean;

    /** Whether the radio is disabled */
    declare disabled: boolean;

    /** Whether the radio is invalid */
    declare invalid: boolean;

    /** The helper text for the radio */
    declare helperText?: string;

    /** For SSR support with slots, sets whether the helper-text slot is occupied */
    declare withHelperText: boolean;

    /** The style of background the radio is on */
    declare backgroundType: "dynamic" | "light" | "dark";

    /** The size of the radio */
    declare size: "small" | "base";

    constructor() {
        super();
        this.checked = false;
        this.backgroundType = "dynamic";
        this.size = "base";
        this.invalid = false;
        this.disabled = false;
        this.withHelperText = false;
    }

    connectedCallback() {
        super.connectedCallback();

        this.setAttribute("role", "radio");
    }

    willUpdate(changed: PropertyValues) {
        super.willUpdate(changed);

        if (!this.hasSlotContent("helper-text")) {
            this.withHelperText = Boolean(
                this.helperText && this.helperText.length > 0
            );
        }
    }

    update(changed: PropertyValues) {
        super.update(changed);

        if (changed.has("checked")) {
            this.setAttribute("aria-checked", String(this.checked));
        }

        if (changed.has("disabled")) {
            this.setAttribute("aria-disabled", String(this.disabled));
        }

        if (changed.has("invalid")) {
            this.setAttribute("aria-invalid", String(this.invalid));
        }
    }

    handleEvent(event: Event) {
        const { intention, target } = this.findClosestIntention(event);

        if (intention === "HELPER_TEXT_SLOT_CHANGE") {
            if (!(target instanceof HTMLSlotElement)) return;
            if (target.name === "helper-text") {
                this.withHelperText = this.hasSlotContent("helper-text");
            }
        }
    }
}

ClgRadio.define("clg-radio");

declare global {
    interface HTMLElementTagNameMap {
        "clg-radio": ClgRadio;
    }
}
