import {
    CollageElement,
    type PropertyDeclarations,
} from "collage/web-components/internal/CollageElement";
import template from "template!collage/clg-star-seller-signal";
import "collage/web-components/components/icon/clg-icon";

/**
 * @tagname clg-star-seller-signal
 *
 * @dependency clg-icon
 */
export class ClgStarSellerSignal extends CollageElement {
    protected static template = template;

    /** How strongly the signal should appear */
    declare variant: "default" | "strong" | "subtle";
    /** Toggles the size modifier to increase the signal size */
    declare size: "base" | "large";

    static override properties: PropertyDeclarations = {
        variant: { type: String, reflect: true },
        size: { type: String, reflect: true },
    };

    constructor() {
        super();
        this.size = "base";
        this.variant = "default";
    }
}

ClgStarSellerSignal.define("clg-star-seller-signal");

declare global {
    interface HTMLElementTagNameMap {
        "clg-star-seller-signal": ClgStarSellerSignal;
    }
}
