import {
    nonDefaultStringConverter,
    type PropertyDeclarations,
} from "collage/web-components/internal/CollageElement";
import template from "template!collage/clg-icon";
import { ClgBaseIcon } from "collage/web-components/internal/base-icon";
import type { CoreIconName } from "collage/web-components/internal/icons";

/**
 * @tagname clg-icon
 */
export class ClgIcon extends ClgBaseIcon {
    protected static override template = template;

    static override properties: PropertyDeclarations = {
        size: {
            type: String,
            reflect: true,
            converter: nonDefaultStringConverter("base"),
        },
    };

    /**
     * The name of the icon to draw.
     * @required
     */
    declare name: CoreIconName;

    /**
     * Size of the icon
     */
    declare size?: "smallest" | "smaller" | "base" | "larger" | "largest";

    constructor() {
        super();
        this.size = "base";
    }

    protected getIconUrl(name: string): string {
        return this.getBasePath(`core/${name}.svg`);
    }

    protected get root() {
        return this.shadowRoot;
    }
}

ClgIcon.define("clg-icon");

declare global {
    interface HTMLElementTagNameMap {
        "clg-icon": ClgIcon;
    }
}
