import {
    type PropertyDeclarations,
    type PropertyValues,
} from "collage/web-components/internal/CollageElement";
import template from "template!collage/clg-shape";
import { ClgBaseIcon } from "collage/web-components/internal/base-icon";

export type Shapes =
    | "special_shape_01"
    | "special_shape_02"
    | "special_shape_03"
    | "special_shape_04"
    | "special_shape_05"
    | "special_shape_06"
    | "special_shape_07"
    | "special_shape_08";

/**
 * @tagname clg-shape
 */
export class ClgShape extends ClgBaseIcon {
    protected static override template = template;

    static override properties: PropertyDeclarations = {
        size: { type: String, reflect: true },
    };

    /**
     * The name of the shape to draw.
     * @required
     */
    declare name: Shapes;

    /**
     * Size of the shape
     */
    declare size: "base" | "larger" | "largest";

    constructor() {
        super();
        this.size = "base";
    }

    protected getIconUrl(name: string): string {
        return this.getBasePath(`shapes/${name}.svg`);
    }

    protected get root() {
        return this.shadowRoot;
    }

    firstUpdated(changed: PropertyValues) {
        super.firstUpdated(changed);

        this.shadowRoot?.querySelector("svg")?.setAttribute("aria-hidden", "true");
    }
}

ClgShape.define("clg-shape");

declare global {
    interface HTMLElementTagNameMap {
        "clg-shape": ClgShape;
    }
}
