import {
    CollageElement,
    type PropertyDeclarations,
    type Validators,
    required,
} from "collage/web-components/internal/CollageElement";
import template from "template!collage/clg-dot-indicator";

/**
 * @tagname clg-dot-indicator
 *
 */
export class ClgDotIndicator extends CollageElement {
    protected static template = template;

    /**
     * Priority of the element marked by the color
     * @required
     */
    declare color: "important" | "highlight";
    /** Whether the badge has a border */
    declare border: boolean;

    static override properties: PropertyDeclarations = {
        color: { type: String, reflect: true },
        border: { type: Boolean, reflect: true },
    };

    protected static validators: Validators = {
        color: required,
    };

    constructor() {
        super();
        this.border = false;
    }
}

ClgDotIndicator.define("clg-dot-indicator");

declare global {
    interface HTMLElementTagNameMap {
        "clg-dot-indicator": ClgDotIndicator;
    }
}
