import {
    CollageElement,
    type PropertyDeclarations,
    type Validators,
    required,
} from "collage/web-components/internal/CollageElement";
import template from "template!collage/clg-slot-card";

/**
 * @tagname clg-slot-card
 * @description A card component that can be used to display content in a card-like format.
 * When href is set, only the title (slot="title") is wrapped in the link for better screen-reader
 * experience; the whole card remains clickable via CSS (stretched link pseudo-element).
 * The link's accessible name comes from the title slot content.
 *
 * @slot title - Content wrapped by the link (e.g. card title). Use when href is set.
 * @slot - Other card content (description, image, buttons, etc.)
 *
 * @example
 * ```html
 * <clg-slot-card href="/listing/123">
 *     <h3 slot="title">Product title</h3>
 *     <p>Price and description</p>
 * </clg-slot-card>
 * ```
 */
export class ClgSlotCard extends CollageElement {
    protected static override template = template;

    protected static validators: Validators = { href: required };

    static override properties: PropertyDeclarations = {
        border: { type: Boolean, reflect: true },
        target: { type: String, reflect: true },
        href: { type: String, reflect: true },
        rel: { type: String, reflect: true },
    };

    /** Whether the card has a border */
    declare border: boolean;
    /** Where to display the linked URL */
    declare target?: "_self" | "_blank" | "_parent" | "_top" | "unfencedTop";
    /**
     * The URL that the hyperlink points to.
     * @required
     */
    declare href: string;
    /** The relationship of the linked URL (e.g. "noopener noreferrer") */
    declare rel?: string;

    constructor() {
        super();
        this.addEventListener("click", this.#onClick);
    }

    #onClick = (event: Event) => {
        const target = event.target;
        if (!(target instanceof HTMLElement)) return;
        if (target.closest("clg-slot-card") !== this) return;
        this.#getLink()?.click();
    };

    #getLink = () => {
        return this.shadowRoot?.querySelector<HTMLAnchorElement>(
            ".clg-slot-card__link"
        );
    };
}

ClgSlotCard.define("clg-slot-card");

declare global {
    interface HTMLElementTagNameMap {
        "clg-slot-card": ClgSlotCard;
    }
}
