import {
    CollageFormElement,
    hasContent,
    required,
    type PropertyDeclarations,
    type PropertyValues,
    type Validators,
} from "collage/web-components/internal/CollageFormElement";
import template from "template!collage/clg-radio-group";
import { ClgRadio } from "collage/web-components/components/radio/clg-radio";
import { RovingTabindexController } from "collage/web-components/reactive-controllers/RovingTabindexController";
import { emptyInputErrorMsg } from "collage/web-components/internal/translations";

const DESCRIBEDBY_IDS = {
    ERROR: "error-message",
    CAPTION: "caption",
    HELPER: "helper-text",
};

/**
 * @tagname clg-radio-group
 *
 * A container for `clg-radio` elements that manages selection and shared attributes.
 *
 * @slot - clg-radio elements
 * @slot label - The label for the radio group
 * @slot helper-text - The helper text for the radio group
 * @slot caption - The caption for the radio group
 */
export class ClgRadioGroup extends CollageFormElement {
    protected static template = template;

    protected static validators: Validators<ClgRadioGroup> = {
        label: { property: required, slot: hasContent },
    };

    static override properties: PropertyDeclarations = {
        variant: { type: String, reflect: true },
        value: { type: String },
        disabled: { type: Boolean, reflect: true },
        orientation: { type: String, reflect: true },
        required: { type: Boolean, reflect: true },
        size: { type: String, reflect: true },
        backgroundType: {
            type: String,
            reflect: true,
            attribute: "background-type",
        },
    };

    /** Visual style variant, default is subtle */
    declare variant: "subtle" | "strong";

    /** Currently selected radio value */
    declare value: string;

    /** Disables/enables all radios in the group */
    declare disabled: boolean;

    /** Whether the radio group is required */
    declare required: boolean;

    /** The size of the radio group */
    declare size: "small" | "base";

    /** Visual/ARIA orientation */
    declare orientation: "horizontal" | "vertical";

    /** The style of background the radio group is on */
    declare backgroundType: "dynamic" | "light" | "dark";

    /** The roving tabindex controller for the radio group */
    #roving?: RovingTabindexController<ClgRadio>;

    get #radios() {
        return Array.from(this.querySelectorAll<ClgRadio>("clg-radio"));
    }

    get #radioGroup() {
        return this.renderRoot.querySelector<HTMLElement>('[role="radiogroup"]');
    }

    constructor() {
        super();
        this.variant = "strong";
        this.value = this.getAttribute("value") ?? "";
        this.disabled = false;
        this.backgroundType = "dynamic";
        this.size = "base";
        this.orientation = "vertical";
    }

    override willUpdate(changed: PropertyValues) {
        super.willUpdate(changed);

        if (!this.hasUpdated) {
            const checkedRadio =
                this.querySelector<ClgRadio>("clg-radio[checked]") ||
                this.#radios.find((radio) => radio.checked) ||
                null;
            const checkedRadioValue = checkedRadio ? checkedRadio.value : "";
            // Defer to checked item over the this element's value
            this.value = checkedRadioValue || this.value;
            // Make sure that the radio is actually checked
            if (this.value && this.value !== checkedRadioValue) {
                const toBeSelectedRadio =
                    this.querySelector<ClgRadio>(
                        `clg-radio[value="${this.value}"]`
                    ) || this.#radios.find((radio) => radio.value === this.value);
                if (toBeSelectedRadio) {
                    toBeSelectedRadio.checked = true;
                }
            }
        }

        this.validate();
    }

    override update(changed: PropertyValues) {
        super.update(changed);

        if (changed.has("value")) {
            this.internals.setFormValue(this.value);
        }

        this.#syncRadios();
        this.#updateDescribedByIds();
    }

    connectedCallback() {
        super.connectedCallback();

        this.addEventListener("click", this.#onClick);
    }

    override firstUpdated(changed: PropertyValues) {
        super.firstUpdated(changed);

        const observer = new MutationObserver(() => this.#handleChildrenChanged());
        observer.observe(this, {
            childList: true,
            subtree: true,
            attributes: true,
        });
        this.onDisconnect(() => {
            observer?.disconnect();
        });

        this.#roving = new RovingTabindexController(this, {
            focusInIndex: (elements: ClgRadio[]) => {
                return elements.findIndex((el) => {
                    return this.value
                        ? !el.disabled && el.value === this.value
                        : !el.disabled;
                });
            },
            direction: () => this.orientation,
            elements: () => this.#radios,
            isFocusableElement: (el) => !el.hasAttribute("disabled"),
            // When roving to a new radio, update the selected value to the newly focused radio
            elementEnterAction: (el) => {
                if (!(el instanceof ClgRadio)) return;
                this.#handleRadioClick(el);
            },
        });

        this.#roving.manage();
    }

    protected override getValidity() {
        const hasCustomValidity = this.customValidityMessage.length > 0;

        const isMissing = this.required && this.value === "";

        if (!hasCustomValidity && !isMissing) {
            if (!this.error) {
                // Preserve invalid state if error property is used
                this.invalid = false;
                this.validationMessage = "";
            }
            return { flags: {} };
        }

        const validationMessage = hasCustomValidity
            ? this.getCustomValidity()
            : isMissing
            ? emptyInputErrorMsg
            : "";
        const flags: ValidityStateFlags = {
            customError: hasCustomValidity,
            valueMissing: isMissing,
        };

        if (!this.error) {
            // Preserve invalid state if error property is used
            // Don't show error state if not touched
            this.invalid = this.touched;
            this.validationMessage = validationMessage;
        }

        return { flags, message: validationMessage };
    }

    #syncRadios() {
        for (const radio of this.#radios) {
            radio.variant = this.variant;
            radio.backgroundType = this.backgroundType;
            radio.invalid = this.invalid ?? false;
            radio.size = this.size;
            radio.disabled = this.disabled;
            const shouldBeChecked = radio.value === this.value && this.value !== "";
            radio.checked = shouldBeChecked;
        }
    }

    #updateDescribedByIds() {
        const ids: string[] = [];
        if (this.invalid) {
            ids.push(DESCRIBEDBY_IDS.ERROR);
        }
        if (this.withCaption) {
            ids.push(DESCRIBEDBY_IDS.CAPTION);
        }
        if (this.withHelperText) {
            ids.push(DESCRIBEDBY_IDS.HELPER);
        }

        if (ids.length > 0) {
            this.#radioGroup?.setAttribute("aria-describedby", ids.join(" "));
        } else {
            this.#radioGroup?.removeAttribute("aria-describedby");
        }
    }

    #handleInput = () => {
        return !this.dispatchEvent(
            new Event("input", { bubbles: true, composed: true, cancelable: true })
        );
    };
    #handleChange = () => {
        return !this.dispatchEvent(
            new Event("change", { bubbles: true, composed: true, cancelable: true })
        );
    };

    /** Handle a list item click/activation */
    #handleRadioClick(item: ClgRadio): void {
        // If the radio group or radio is disabled, don't allow the click
        if (this.disabled || item.disabled) return;
        const clickedValue = item.value ?? "";
        if (this.value !== clickedValue) {
            const oldValue = this.value;
            this.value = clickedValue;
            const inputPrevented = this.#handleInput();
            const changePrevented = this.#handleChange();
            if (inputPrevented || changePrevented) {
                this.value = oldValue;
            } else {
                for (const radioItem of this.#radios) {
                    radioItem.checked = radioItem.value === clickedValue;
                }
            }
        }
    }

    #onClick: EventListener = (ev) => {
        const target = ev.target;
        if (!(target instanceof Element)) return;
        const el = target.closest("clg-radio");
        if (!el || !this.contains(el)) return;
        this.#handleRadioClick(el);
    };

    #handleChildrenChanged = () => {
        this.#roving?.clearElementCache();
        this.#syncRadios();
    };

    protected formResetCallback() {
        super.formResetCallback();
        // Restore initial/default value on reset
        this.value = this.getAttribute("value") ?? "";
    }

    protected formStateRestoreCallback(state: string | File | FormData) {
        // eslint-disable-next-line @typescript-eslint/consistent-type-assertions
        this.value = state as string;
    }

    disconnectedCallback() {
        super.disconnectedCallback();
        this.removeEventListener("click", this.#onClick);
        this.#roving?.unmanage();
    }

    public override focus(): void {
        this.#roving?.focus();
    }
}

ClgRadioGroup.define("clg-radio-group");

declare global {
    interface HTMLElementTagNameMap {
        "clg-radio-group": ClgRadioGroup;
    }
}
