import { CollageElement } from "collage/web-components/internal/CollageElement";
import template from "template!collage/clg-list-item";

/**
 * @tagname clg-list-item
 *
 * @slot - list content
 */
export class ClgListItem extends CollageElement {
    protected static override template = template;

    connectedCallback() {
        super.connectedCallback();
        this.setAttribute("role", "listitem");
    }
}

ClgListItem.define("clg-list-item");

declare global {
    interface HTMLElementTagNameMap {
        "clg-list-item": ClgListItem;
    }
}
