import type { PropertyValues, ReactiveElement } from "@lit/reactive-element";

// eslint-disable-next-line @typescript-eslint/no-explicit-any
type Constructor<T = object> = abstract new (...args: any[]) => T;

/** Constant for the default/unnamed slot */
export const DEFAULT_SLOT = "[default]" as const;

/** Context passed to custom validators */
export interface ValidatorContext {
    tagName: string;
    key: string;
}

/** Custom property validator function */
export type PropertyValidator<
    T extends HTMLElement & PropertySlotValidationInterface = HTMLElement &
        PropertySlotValidationInterface
> = (
    this: T,
    value: unknown,
    context: ValidatorContext
) => string | null | undefined;

/** Custom slot validator function */
export type SlotValidator<
    T extends HTMLElement & PropertySlotValidationInterface = HTMLElement &
        PropertySlotValidationInterface
> = (
    this: T,
    slot: HTMLSlotElement | null,
    context: ValidatorContext
) => string | null | undefined;

/** Default property validator - checks that value is not null, undefined, or empty string */
export const required: PropertyValidator = function (value, context) {
    if (value === undefined || value === null || value === "") {
        return `${context.tagName}: Expected to have a \`${context.key}\` property.`;
    }
    return undefined;
};

/** Default slot validator - checks that the slot has content */
export const hasContent: SlotValidator = function (_slot, context) {
    if (!this.hasSlotContent(context.key)) {
        return `${context.tagName}: Expected to have content in the \`${context.key}\` slot.`;
    }
    return undefined;
};

/** Configuration for a single validator entry */
export interface ValidatorConfig<
    T extends HTMLElement & PropertySlotValidationInterface = HTMLElement &
        PropertySlotValidationInterface
> {
    /** Property validator - use `required` or a custom function */
    property?: PropertyValidator<T>;
    /** Slot validator - use `hasContent` or a custom function */
    slot?: SlotValidator<T>;
}

/** Type for validator keys */
type ValidatorKey = string | typeof DEFAULT_SLOT;

/** Schema of validators keyed by property/slot name */
export type Validators<
    T extends HTMLElement & PropertySlotValidationInterface = HTMLElement &
        PropertySlotValidationInterface,
    K extends string = string
> = Partial<
    Record<K, ValidatorConfig<T> | PropertyValidator<T> | SlotValidator<T>>
> & {
    [DEFAULT_SLOT]?: ValidatorConfig<T> | SlotValidator<T>;
};

export interface PropertySlotValidationInterface {
    hasSlotContent(slotName: string | typeof DEFAULT_SLOT): boolean;
}

export const PropertySlotValidationMixin = <T extends Constructor<ReactiveElement>>(
    superClass: T
) => {
    abstract class PropertySlotValidationMixinClass extends superClass {
        protected static validators: Validators = {};

        firstUpdated(changed: PropertyValues) {
            super.firstUpdated(changed);
            this.#validate();
        }

        #validate() {
            if (!true && !false) return;

            // eslint-disable-next-line @typescript-eslint/consistent-type-assertions
            const ctor = this
                .constructor as typeof PropertySlotValidationMixinClass;
            const { validators } = ctor;

            if (!validators) return;

            const validateProperty = (
                key: ValidatorKey,
                validator: PropertyValidator
            ): string | undefined => {
                const keyStr = typeof key === "string" ? key : "";
                // @ts-expect-error dynamic property access
                const value = this[keyStr];
                const context: ValidatorContext = {
                    tagName: this.localName,
                    key,
                };
                return validator.call(this, value, context) ?? undefined;
            };

            const validateSlot = (
                key: ValidatorKey,
                validator: SlotValidator
            ): string | undefined => {
                const context: ValidatorContext = {
                    tagName: this.localName,
                    key,
                };
                const selector =
                    key === DEFAULT_SLOT ? "slot:not([name])" : `slot[name=${key}]`;
                const slot =
                    this.shadowRoot?.querySelector<HTMLSlotElement>(selector) ||
                    null;
                return validator.call(this, slot, context) ?? undefined;
            };

            const normalizeConfig = (
                config: ValidatorConfig | PropertyValidator | SlotValidator
            ): ValidatorConfig => {
                // Shorthand: `required` alone means property validation
                if (config === required) return { property: required };
                // Shorthand: `hasContent` alone means slot validation
                if (config === hasContent) return { slot: hasContent };
                // Already a full config object
                return { ...config };
            };

            Object.keys(validators).forEach((key) => {
                // eslint-disable-next-line @typescript-eslint/consistent-type-assertions
                const rawConfig = validators[key as keyof typeof validators];
                if (!rawConfig) return;

                const { property, slot } = normalizeConfig(rawConfig);

                const propError = property
                    ? validateProperty(key, property)
                    : undefined;
                const slotError = slot ? validateSlot(key, slot) : undefined;

                // If both validators exist, only throw if both fail (throw property error)
                // If only one validator exists, throw if it fails
                if (property && slot) {
                    if (propError && slotError) {
                        throw new Error(propError);
                    }
                    return;
                } else if (propError) {
                    throw new Error(propError);
                } else if (slotError) {
                    throw new Error(slotError);
                }
            });
        }

        /** Determine whether the slot with the given name is occupied */
        hasSlotContent(slotName: string | typeof DEFAULT_SLOT): boolean {
            if (slotName === DEFAULT_SLOT) {
                return [...this.childNodes].some((node) => {
                    if (
                        node.nodeType === Node.TEXT_NODE &&
                        // If it's a text node, it will have textContent
                        // eslint-disable-next-line @typescript-eslint/no-non-null-assertion
                        node.textContent!.trim() !== ""
                    ) {
                        return true;
                    }

                    if (node.nodeType === Node.ELEMENT_NODE) {
                        // If it's an element node, it's an HTMLElement
                        // eslint-disable-next-line @typescript-eslint/consistent-type-assertions
                        const el = node as HTMLElement;

                        // If it doesn't have a slot attribute, it's part of the default slot
                        if (!el.hasAttribute("slot")) {
                            return true;
                        }
                    }

                    return false;
                });
            }

            return this.querySelector(`[slot="${slotName}"]`) !== null;
        }
    }

    // eslint-disable-next-line @typescript-eslint/consistent-type-assertions
    return PropertySlotValidationMixinClass as Constructor<PropertySlotValidationInterface> &
        T;
};
