import {
    CollageElement,
    type PropertyDeclarations,
    type PropertyValues,
} from "collage/web-components/internal/CollageElement";
import template from "template!collage/clg-selectable-list-item";
import "collage/web-components/components/icon/clg-icon";

/**
 * @tagname clg-selectable-list-item
 *
 * @dependency clg-icon
 *
 * @slot - list content
 * @slot graphic - graphic content
 * @slot icon - icon content
 * @slot title - title content
 * @slot subtitle - subtitle content
 */
export class ClgSelectableListItem extends CollageElement {
    protected static override template = template;

    static override properties: PropertyDeclarations = {
        variant: { type: String, reflect: true },
        value: { type: String, reflect: true },
        selected: { type: Boolean, reflect: true },
    };
    /**
     * Visual style variant
     * @default "subtle"
     */
    declare variant: "subtle" | "strong";

    /** Value associated with this option */
    declare value: string;

    /** Whether this item is selected */
    declare selected: boolean;

    constructor() {
        super();
        this.variant = "subtle";
        this.value = "";
        this.selected = false;
    }

    get titleSlot(): HTMLSlotElement | null {
        const root = this.shadowRoot;
        if (!root) return null;
        return root.querySelector<HTMLSlotElement>('slot[name="title"]');
    }

    #syncAriaLabelFromTitleSlot(): void {
        if (!this.titleSlot) return;
        const assigned = this.titleSlot.assignedElements({ flatten: true });
        if (assigned.length === 0) return;
        const textContent = assigned[0]?.textContent?.trim() ?? "";
        if (textContent.length === 0) return;
        this.setAttribute("aria-label", textContent);
    }

    connectedCallback() {
        super.connectedCallback();

        this.setAttribute("role", "option");
    }

    override update(changed: PropertyValues) {
        super.update(changed);

        if (changed.has("selected")) {
            this.setAttribute("aria-selected", this.selected ? "true" : "false");
        }

        // We'll wait until slots are occupied to sync the aria-label which is why this is here and not in connectedCallback
        this.#syncAriaLabelFromTitleSlot();
    }
}

ClgSelectableListItem.define("clg-selectable-list-item");

declare global {
    interface HTMLElementTagNameMap {
        "clg-selectable-list-item": ClgSelectableListItem;
    }
}
