import {
    CollageElement,
    type PropertyDeclarations,
    type Validators,
    required,
} from "collage/web-components/internal/CollageElement";
import template from "template!collage/clg-logo-button";
import "collage/web-components/components/logo/clg-logo";
import "collage/web-components/components/loading-spinner/clg-loading-spinner";
import { LoadingButtonController } from "collage/web-components/reactive-controllers/LoadingButtonController";
import { forwardClicksInTests } from "collage/web-components/internal/forward-clicks-in-tests";

/**
 * @tagname clg-logo-button
 * @summary A button with a logo icon, used for sign-in and payment options.
 *
 * @dependency clg-loading-spinner
 * @dependency clg-logo
 *
 * @slot - button content
 */
export class ClgLogoButton extends CollageElement {
    protected static override template = template;
    static shadowRootOptions = {
        ...CollageElement.shadowRootOptions,
        delegatesFocus: true,
    };
    protected static validators: Validators = { variant: required };

    static override properties: PropertyDeclarations = {
        variant: { type: String, reflect: true },
        name: { type: String, reflect: true },
        value: { type: String, reflect: true },
        disabled: { type: Boolean, reflect: true },
        loading: { type: Boolean, reflect: true },
        backgroundType: {
            type: String,
            reflect: true,
            attribute: "background-type",
        },
        type: { type: String, reflect: true },
    };

    /**
     * Visual look of the button
     * @required
     */
    declare variant: "payment" | "signin" | "apple-pay" | "google-pay";
    /** The name of the button */
    declare name: string;
    /** The value of the button */
    declare value: string | null;
    /** Whether or not the button is interactive */
    declare disabled: boolean;
    /** If true, will display a loading spinner */
    declare loading: boolean;
    /** The style of background the button is on */
    declare backgroundType: "dynamic" | "light" | "dark";
    /** The button's `type` attribute */
    declare type: "button" | "submit" | "reset";

    static delegatedEvents = ["click"];

    constructor() {
        super();
        this.disabled = false;
        this.loading = false;
        this.backgroundType = "dynamic";
        this.type = "button";
        this.value = "";

        new LoadingButtonController(this, () => this.#button);
        forwardClicksInTests(this, () => this.#button);
    }

    get #button() {
        return this.shadowRoot?.querySelector<HTMLButtonElement>(
            "[data-logo-button-root]"
        );
    }

    override connectedCallback() {
        super.connectedCallback();
        // Dark mode (only for checkout and sign in flows)
        // If we are in dark mode, add attribute backgroundType="dark" for styling
        if (document.body.getAttribute("data-clg-mode") === "dark") {
            this.setAttribute("background-type", "dark");
        }
    }

    public focus(opts?: FocusOptions) {
        if (this.#button) {
            this.#button.focus(opts);
        } else {
            this.updateComplete.then(() => {
                this.#button?.focus(opts);
            });
        }
    }
    public blur() {
        if (this.#button) {
            this.#button.blur();
        } else {
            this.updateComplete.then(() => {
                this.#button?.blur();
            });
        }
    }
    public click() {
        if (this.#button) {
            this.#button.click();
        } else {
            this.updateComplete.then(() => {
                this.#button?.click();
            });
        }
    }
}

ClgLogoButton.define("clg-logo-button");

declare global {
    interface HTMLElementTagNameMap {
        "clg-logo-button": ClgLogoButton;
    }
}
