import {
    CollageElement,
    type PropertyDeclarations,
    type Validators,
    required,
} from "collage/web-components/internal/CollageElement";
import template from "template!collage/clg-card";

/**
 * @tagname clg-card
 * @summary A card component that displays content in a card-like format.
 * When href is set, only the title (slot="title") is wrapped in the link so that
 * screen reader users hear only the card title when navigating by link; the whole
 * card remains clickable via CSS (stretched link pseudo-element).
 *
 * @slot image - A slot for image content or a clg-image-tile element.
 * @slot title - Content wrapped by the link (e.g. card title). Use when href is set.
 * @slot - A slot for content like a description, metadata, etc.
 *
 * @example
 * ```html
 * <clg-card href="/listing/123">
 *    <img slot="image" src="https://via.placeholder.com/150" alt="Placeholder image" />
 *    <h3 slot="title">Card title</h3>
 *    <p>Card description</p>
 * </clg-card>
 * ```
 */
export class ClgCard extends CollageElement {
    protected static override template = template;

    protected static validators: Validators = { href: required };

    static override properties: PropertyDeclarations = {
        imageLayout: {
            type: String,
            reflect: true,
            attribute: "image-layout",
        },
        container: { type: String, reflect: true },
        href: { type: String, reflect: true },
        target: { type: String, reflect: true },
        rel: { type: String, reflect: true },
    };

    /** Position of the image in the card */
    declare imageLayout: "top" | "start" | "end";

    /** Container type for the card */
    declare container?:
        | "elevated"
        | "elevated-padded"
        | "elevated-no-border"
        | "elevated-padded-no-border";

    /**
     * The URL that the hyperlink points to.
     * @required
     */
    declare href: string;
    /** Where to display the linked URL */
    declare target?: "_self" | "_blank" | "_parent" | "_top" | "unfencedTop";
    /** The relationship of the linked URL as space-separated link types. */
    declare rel?: string;

    constructor() {
        super();
        this.imageLayout = "top";
        this.addEventListener("click", this.#onClick);
    }

    #onClick = (event: Event) => {
        const target = event.target;
        if (!(target instanceof HTMLElement)) return;
        if (target.closest("clg-card") !== this) return;
        this.#getStretchedLink()?.click();
    };

    #getStretchedLink(): HTMLAnchorElement | null {
        return (
            this.shadowRoot?.querySelector<HTMLAnchorElement>(".clg-card__link") ??
            null
        );
    }
}

ClgCard.define("clg-card");

declare global {
    interface HTMLElementTagNameMap {
        "clg-card": ClgCard;
    }
}
