import {
    CollageElement,
    type PropertyDeclarations,
    type Validators,
    required,
} from "collage/web-components/internal/CollageElement";
import template from "template!collage/clg-signal-banner";
import "collage/web-components/components/banner/clg-banner-base";

/**
 * @tagname clg-signal-banner
 *
 * @dependency clg-banner-base
 *
 * @slot - banner message
 * @slot icon - icon
 * @slot title - banner title
 *
 * @fires {ClgCloseEvent} clg-close - Event fired when the close button is clicked.
 */
export class ClgSignalBanner extends CollageElement {
    protected static template = template;

    /**
     * Variant to define urgency of the message (subtle outline style or strong full bleed background)
     * @required
     */
    declare variant: "subtle" | "strong";
    /**
     * Color variants based on the purpose of the message.
     * @required
     */
    declare color: "neutral" | "highlight";
    /**
     * Buttons variants for different call to action use cases.
     */
    declare buttons?: "buttonGroup" | "inlineButton" | "dismissOnly" | "none";
    /**
     * Whether the banner is open or not (for use with open-close events)
     */
    declare open?: boolean;

    static override properties: PropertyDeclarations = {
        variant: { type: String, reflect: true },
        color: { type: String, reflect: true },
        buttons: { type: String, reflect: true },
        open: { type: Boolean, reflect: true },
    };

    protected static validators: Validators = {
        variant: required,
        color: {
            property(value, context) {
                if (value !== "neutral" && value !== "highlight") {
                    return `${context.tagName}: color must be 'neutral' or 'highlight'`;
                }
                return null;
            },
        },
    };

    constructor() {
        super();
        this.buttons = "none";
        this.open = false;
    }
}

ClgSignalBanner.define("clg-signal-banner");

declare global {
    interface HTMLElementTagNameMap {
        "clg-signal-banner": ClgSignalBanner;
    }
}
