import type { TNode, TTree } from "translator/mini-mustache/types";

type Children<B, V> = (B | V | string)[];

/**
 * Visitor for transforming a tree. The generics are:
 *   - T: The ultimate type of the transformed tree. This is what `transform()`
 *        will return.
 *   - B: What type block nodes will be transformed into.
 *   - V: What type variable nodes will be transformed into.
 *   - C: Shared context object that will be passed to all visit methods.
 *
 * Note that tree and block nodes can contain strings, variable nodes, and
 * other block nodes: therefore `visitTree()` and `visitBlock()` will be called
 * with `Array<B | V | string>`.
 */
export interface Transformer<T, B, V, C> {
    visitTree(children: Children<B, V>, context: C): T;
    visitBlock(variable: string, children: Children<B, V>, context: C): B;
    visitVariable(variable: string, context: C): V;
}

function transformChildren<B, V, C>(
    transformer: Transformer<unknown, B, V, C>,
    children: TNode[],
    context: C
): Children<B, V> {
    return children.map((child) => {
        if (typeof child === "string") {
            return child;
        }
        switch (child.type) {
            case "block":
                return transformer.visitBlock(
                    child.variable,
                    transformChildren(transformer, child.children, context),
                    context
                );
            case "variable":
                return transformer.visitVariable(child.variable, context);
            default:
                // @ts-expect-error: Switch *should* be exhaustive.
                throw new Error(`Unknown node type: ${child.type}`);
        }
    });
}

/**
 * Bottom-up transformation using the visitor pattern. Visit methods of the
 * visitor will be called from the leaves of the tree up to the root.
 */
export default function transform<T, B, V, C>(
    tree: TTree,
    transformer: Transformer<T, B, V, C>,
    context: C
): T {
    return transformer.visitTree(
        transformChildren(transformer, tree.children, context),
        context
    );
}
