import {
    CollageFormElement,
    hasContent,
    required,
    type PropertyDeclarations,
    type PropertyValues,
    type Validators,
} from "collage/web-components/internal/CollageFormElement";
import template from "template!collage/clg-checkbox-group";
import type { ClgCheckbox } from "collage/web-components/components/checkbox/clg-checkbox";
import "collage/web-components/components/icon/clg-icon";

/**
 * @tagname clg-checkbox-group
 *
 * @dependency clg-icon
 *
 * @slot - clg-checkbox elements
 * @slot label - The label for the checkbox group
 * @slot helper-text - Additional instructions or context for the text field
 * @slot caption - Additional instructions or context for the text field
 */
export class ClgCheckboxGroup extends CollageFormElement {
    protected static template = template;

    protected static validators: Validators<ClgCheckboxGroup> = {
        label: { property: required, slot: hasContent },
    };

    /** Size of the checkbox group */
    declare size: "base" | "small";
    /** Whether the checkbox group is required */
    declare required: boolean;
    /** Whether the checkbox group is optional */
    declare optional: boolean;
    /** Visual/ARIA orientation of the checkbox group */
    declare orientation: "horizontal" | "vertical";

    static override properties: PropertyDeclarations = {
        size: { type: String, reflect: true },
        required: { type: Boolean, reflect: true },
        optional: { type: Boolean, reflect: true },
        orientation: { type: String, reflect: true },
    };

    // Get the checkboxes within the group
    #getCheckboxes(): ClgCheckbox[] {
        return Array.from(this.querySelectorAll<ClgCheckbox>("clg-checkbox"));
    }

    constructor() {
        super();
        this.size = "base";
        this.required = false;
        this.optional = false;
        this.orientation = "vertical";
        this.helperText = "";
        this.caption = "";
    }

    override willUpdate(changed: PropertyValues) {
        super.willUpdate(changed);
        this.validate();
    }

    override update(changed: PropertyValues) {
        super.update(changed);
        if (changed.has("invalid")) {
            this.#syncInvalid();
        }
    }

    connectedCallback() {
        super.connectedCallback();
        this.addEventListener("change", this.#onChange);
    }

    // If one of the child checkboxes changes, re-check validity
    #onChange = (e: Event) => {
        const target = e.target;
        if (!(target instanceof Element)) return;
        this.validate();
    };

    protected override getValidity() {
        const hasCustomValidity = this.customValidityMessage.length > 0;
        const isMissing = this.required && !this.#hasSelection();

        if (!hasCustomValidity && !isMissing) {
            if (!this.error) {
                // Preserve invalid state if error property is used
                this.invalid = false;
                this.validationMessage = "";
            }
            return { flags: {} };
        }

        const validationMessage = hasCustomValidity
            ? this.getCustomValidity()
            : isMissing
            ? "Please fill out this field."
            : "";

        const flags: ValidityStateFlags = {
            customError: hasCustomValidity,
            valueMissing: isMissing,
        };

        if (!this.error) {
            // Preserve invalid state if error property is used
            // Don't show error state if not touched
            this.invalid = this.touched;
            this.validationMessage = validationMessage;
        }

        return { flags, message: validationMessage };
    }

    // Check if any of the child checkboxes are checked
    #hasSelection(): boolean {
        for (const checkBox of this.#getCheckboxes()) {
            if (checkBox.checked) {
                return true;
            }
        }
        return false;
    }

    #syncInvalid() {
        for (const checkBox of this.#getCheckboxes()) {
            checkBox.error = this.invalid ? this.validationMessage : "";
        }
    }

    protected formResetCallback() {
        super.formResetCallback();
        this.updateComplete.then(() => {
            this.validate();
        });
    }

    disconnectedCallback() {
        super.disconnectedCallback();
        this.removeEventListener("change", this.#onChange);
    }
}

ClgCheckboxGroup.define("clg-checkbox-group");
declare global {
    interface HTMLElementTagNameMap {
        "clg-checkbox-group": ClgCheckboxGroup;
    }
}
