import {
    CollageElement,
    type PropertyDeclarations,
    type Validators,
    required,
} from "collage/web-components/internal/CollageElement";
import template from "template!collage/clg-status-indicator";

/**
 * @element clg-status-indicator
 *
 *  @slot - The status indicator's text content
 *  @slot icon - Icon displayed before the text
 *
 */
export class ClgStatusIndicator extends CollageElement {
    protected static template = template;

    /**
     * The status signified by the color of the badge
     * @required
     */
    declare color: "success" | "warning" | "critical";
    /** The size of the badge */
    declare size: "base" | "large";

    static override properties: PropertyDeclarations = {
        color: { type: String, reflect: true },
        size: { type: String, reflect: true },
    };

    protected static validators: Validators = {
        color: required,
    };

    constructor() {
        super();
        this.size = "base";
    }
}

ClgStatusIndicator.define("clg-status-indicator");

declare global {
    interface HTMLElementTagNameMap {
        "clg-status-indicator": ClgStatusIndicator;
    }
}
