import {
    CollageElement,
    type PropertyDeclarations,
    type PropertyValues,
} from "collage/web-components/internal/CollageElement";
import template from "template!collage/clg-navigational-list";
import type { ClgNavigationalListItem } from "collage/web-components/components/navigational-list/clg-navigational-list-item";

/**
 * @tagname clg-navigational-list
 *
 * @slot title - list title
 * @slot - list content
 */
export class ClgNavigationalList extends CollageElement {
    protected static override template = template;

    static override properties: PropertyDeclarations = {
        variant: { type: String, reflect: true },
        noDivider: { type: Boolean, reflect: true, attribute: "no-divider" },
    };

    /** Visual style variant, default is subtle */
    declare variant?: "subtle" | "strong";
    /** When true, removes item dividers */
    declare noDivider?: boolean;

    static delegatedEvents = ["slotchange"];

    constructor() {
        super();
        this.variant = "subtle";
        this.noDivider = false;
    }

    /** Get all list items */
    #getItems(): ClgNavigationalListItem[] {
        return Array.from(
            this.querySelectorAll<ClgNavigationalListItem>(
                "clg-navigational-list-item"
            )
        );
    }

    /**
     * Sync navigational list variant prop with item variants
     * We need the items to always reflect the list variant if set
     */
    #syncItemVariants(): void {
        const listVariant = this.variant;
        if (!listVariant) return;
        const items = this.#getItems();
        for (const item of items) {
            item.variant = listVariant;
            // Divider handled by parent: toggle 'no-divider' on items
            if (this.noDivider) {
                item.setAttribute("no-divider", "");
            } else {
                item.removeAttribute("no-divider");
            }
        }
    }

    /** Validate the list items are only clg-navigational-list-item children */
    #validateListItems(): void {
        if (!(true || false)) return;
        const invalidListItems = [...this.children].filter((el) => {
            if (el.getAttribute("slot") === "title") return false;
            return el.tagName.toLowerCase() !== "clg-navigational-list-item";
        });
        if (invalidListItems.length > 0) {
            throw new TypeError(
                `clg-navigational-list only accepts clg-navigational-list-item children. Found: ${invalidListItems.length}`
            );
        }
    }

    handleEvent(e: Event) {
        const { intention } = this.findClosestIntention(e);
        if (intention === "SLOT_OCCUPIED") {
            this.#handleSlotChange();
        }
    }

    #handleSlotChange = () => {
        this.#validateListItems();
        this.requestUpdate();
    };

    connectedCallback() {
        super.connectedCallback();
        this.setAttribute("role", "list");
    }

    override update(changed: PropertyValues) {
        super.update(changed);

        this.#syncItemVariants();
    }
}

ClgNavigationalList.define("clg-navigational-list");

declare global {
    interface HTMLElementTagNameMap {
        "clg-navigational-list": ClgNavigationalList;
    }
}
