import template from "template!collage/clg-logo";
import { ClgBaseIcon } from "collage/web-components/internal/base-icon";
import type { LogoIconName } from "collage/web-components/internal/icons";

/**
 * @tagname clg-logo
 *
 * @cssproperty --clg-logo-svg-height - Sets the height of the svg.
 * @cssproperty --clg-logo-svg-width - Sets the width of the svg.
 */
export class ClgLogo extends ClgBaseIcon {
    protected static override template = template;

    /**
     * The name of the icon to draw.
     * @required
     */
    declare name: LogoIconName;

    protected getIconUrl(name: string): string {
        return this.getBasePath(`logo/${name}.svg`);
    }

    protected get root() {
        return this.shadowRoot;
    }
}

ClgLogo.define("clg-logo");

declare global {
    interface HTMLElementTagNameMap {
        "clg-logo": ClgLogo;
    }
}
