import { getActiveElements } from "collage/web-components/internal/getActiveElements";

/**
 * Change the tag of an HTML element while preserving its attributes and child nodes.
 */
export function changeHtmlTag(element: HTMLElement, newTagName: string) {
    const hasFocus = getActiveElements().pop() === element;
    const replacement = document.createElement(newTagName);
    // Copy attributes
    for (const { name, value } of Array.from(element.attributes)) {
        replacement.setAttribute(name, value);
    }
    // move child nodes (preserves state of and  event listeners on child elements)
    while (element.firstChild) {
        replacement.appendChild(element.firstChild);
    }
    element.replaceWith(replacement);
    if (hasFocus) {
        replacement.focus();
    }
    return replacement;
}

/**
 * Toggle a string attribute on an HTML element
 */
export function toggleStringAttribute(
    element: HTMLElement,
    attribute: string,
    value?: string
) {
    if (value) {
        element.setAttribute(attribute, value);
    } else {
        element.removeAttribute(attribute);
    }
}

/**
 * Get the `innerHTML` of a slot element
 */
export function getSlotHtml(slot: HTMLSlotElement): string {
    const nodes = slot.assignedNodes({ flatten: true });
    let innerHtml = "";

    [...nodes].forEach((node) => {
        if (node.nodeType === Node.ELEMENT_NODE) {
            // eslint-disable-next-line @typescript-eslint/consistent-type-assertions
            innerHtml += (node as HTMLElement).outerHTML;
        }

        if (node.nodeType === Node.TEXT_NODE) {
            innerHtml += node.textContent;
        }
    });

    return innerHtml;
}
