import {
    CollageElement,
    type PropertyDeclarations,
    type Validators,
    type PropertyValues,
} from "collage/web-components/internal/CollageElement";
import { ClgCloseEvent } from "collage/web-components/events/open-close";
import { ClgToastGroup } from "collage/web-components/components/toast/clg-toast-group";
import template from "template!collage/clg-toast";

import "collage/web-components/components/icon-button/clg-icon-button";
import "collage/web-components/components/icon/clg-icon";
import type { ClgIconButton } from "collage/web-components/components/icon-button/clg-icon-button";
import type { ClgTextButton } from "collage/web-components/components/text-button/clg-text-button";
import type { ClgIcon } from "collage/web-components/components/icon/clg-icon";

// Accessibility notes:
// - Each toast has a role of "status" or "alert", depending on the variant, and
//   aria-live, so the screen-reader will read its content without being focused.
// - The toast will stay open by default for 5s + 50ms for each character within it.
// - If the toast is hovered over by a mouse, the timer will pause, then restart when
//   the mouse is moved away or focus shifts away.
// - We do not draw focus to any interactive element within the toast automatically,
//   as that would be inconsistent with the status and alert roles. If an action
//   is rendered within the toast, we strongly recommend providing the user alternative
//   means to complete that action, such as with a keyboard shortcut.

const DEFAULT_ACTUAL_DURATION = 5000;
const DEFAULT_DURATION = -1;

/**
 * @tagname clg-toast
 *
 * @dependency clg-icon-button
 * @dependency clg-icon
 *
 * @slot - Text content
 * @slot icon - icon slot
 * @slot action - text button slot
 *
 * @fires {ClgCloseEvent} clg-close - Fired when the toast is dismissed, either by user interaction or by the timer.
 */
export class ClgToast extends CollageElement {
    protected static template = template;

    protected static validators: Validators = {
        action: {
            slot(slot) {
                const assignedNodes = slot?.assignedElements({
                    flatten: true,
                });
                for (const node of assignedNodes ?? []) {
                    if (
                        node.localName !== "clg-text-button" &&
                        !node.querySelector("clg-text-button")
                    ) {
                        return "clg-toast: action slot must contain a <clg-text-button>";
                    }
                }
                return null;
            },
        },
    };

    get #iconSlot() {
        return this.renderRoot.querySelector<HTMLSlotElement>('slot[name="icon"]');
    }

    #animationFrame: number | null = null;
    #isPaused = false;
    #startTime: number | null = null;
    #observer: MutationObserver | null = null;
    /** Actual duration while open, derived from duration property. */
    #duration = DEFAULT_ACTUAL_DURATION;

    /**
     * Color variants based on the purpose of the message.
     * @required
     */
    declare color: "neutral" | "critical";
    /**
     * Length of time in miliseconds before auto-dismiss. Default is calculated based on text length.
     * Set to 0 to disable auto-dismiss.
     * @default 5000
     */
    declare duration: number;
    /**
     * Whether or not the element's icon slot is occupied. This is
     * programmatically determined, but can be useful to set manually
     * if needed before JS runs.
     */
    declare withIcon: boolean;
    /**
     * Sets the icon displayed by the toast. This only applies for the "neutral" variant,
     * the "critical" variant icon is not configurable.
     */
    declare icon: ClgIcon["name"];

    static override properties: PropertyDeclarations = {
        color: { type: String, reflect: true },
        duration: { type: Number },
        withIcon: { type: Boolean, reflect: true, attribute: "with-icon" },
        icon: {},
    };

    static delegatedEvents = ["click", "slotchange"];

    constructor() {
        super();
        this.duration = DEFAULT_DURATION;
        this.withIcon = false;
    }

    connectedCallback() {
        super.connectedCallback();

        this.addEventListener("pointerenter", this.#handleInteractionIn);
        this.addEventListener("pointerleave", this.#handleInteractionOut);
    }

    disconnectedCallback() {
        super.disconnectedCallback();

        this.#stopTimer();

        this.removeEventListener("pointerenter", this.#handleInteractionIn);
        this.removeEventListener("pointerleave", this.#handleInteractionOut);
    }

    override willUpdate(changed: PropertyValues) {
        super.willUpdate(changed);
        this.withIcon = Boolean(this.icon || this.hasSlotContent("icon"));
    }

    override firstUpdated(changed: PropertyValues) {
        super.firstUpdated(changed);

        requestAnimationFrame(() => {
            this.#startTimer();
        });
    }

    override update(changed: PropertyValues<typeof this>) {
        super.update(changed);

        if (changed.has("icon") && this.#iconSlot) {
            this.#iconSlot.innerHTML = this.icon
                ? `<clg-icon name="${this.icon}" size="smaller"></clg-icon>`
                : "";
        }

        if (changed.has("color")) {
            const dismissBtn =
                this.shadowRoot?.querySelector<ClgIconButton>("#dismiss");

            // eslint-disable-next-line @typescript-eslint/consistent-type-assertions
            const actionBtn = this.shadowRoot
                ?.querySelector<HTMLSlotElement>('slot[name="action"]')
                ?.assignedElements({ flatten: true })
                .find((el) => el.tagName.toLowerCase() === "clg-text-button") as
                | ClgTextButton
                | undefined;

            if (this.color === "critical") {
                // https://developer.mozilla.org/en-US/docs/Web/Accessibility/ARIA/Guides/Live_regions#roles_with_implicit_live_region_attributes
                // aria-live="assertive" and role="alert" can cause double-speak on iOS
                this.setAttribute("role", "alert");
                this.removeAttribute("aria-live");
                if (dismissBtn) {
                    dismissBtn.backgroundType = "dark";
                }
                if (actionBtn) {
                    actionBtn.backgroundType = "dark";
                }
            } else {
                this.setAttribute("role", "status");
                this.setAttribute("aria-live", "polite");
                if (dismissBtn) {
                    dismissBtn.backgroundType = "dynamic";
                }
                if (actionBtn) {
                    actionBtn.backgroundType = "dynamic";
                }
            }
        }
    }

    #calcActualDuration(): number {
        if (this.duration !== DEFAULT_DURATION) return this.duration;

        const slot =
            this.shadowRoot?.querySelector<HTMLSlotElement>("slot:not([name])");
        if (!slot) return DEFAULT_ACTUAL_DURATION;

        const textLength = slot
            .assignedNodes({ flatten: true })
            .reduce((acc, node) => acc + (node.textContent?.length ?? 0), 0);

        // Add 50ms for each character, with a minimum of 5 seconds
        return DEFAULT_ACTUAL_DURATION + (textLength ?? 0) * 50;
    }

    /**
     * Closes the toast and removes it from the document.
     */
    dismiss() {
        return this.#dismiss("programmatic");
    }

    async #dismiss(source: "user" | "timer" | "programmatic") {
        const handleDismiss = async () => {
            await this.#waitForGroupTransition();
            this.remove();
        };

        if (source === "user") {
            const defaultPrevented = !this.dispatchEvent(
                new ClgCloseEvent({ origin: "user" }, { cancelable: true })
            );
            if (!defaultPrevented) {
                return handleDismiss();
            }
        } else {
            this.dispatchEvent(new ClgCloseEvent({ origin: "internal" }));
            return handleDismiss();
        }
    }

    /**
     * Starts the auto-dismiss timer.
     */
    #startTimer() {
        this.#duration = this.#calcActualDuration();

        if (this.#duration > 0 && Number.isFinite(this.#duration)) {
            if (!this.#observer) {
                this.#observer = new MutationObserver(() => {
                    this.#stopTimer();
                    requestAnimationFrame(() => {
                        this.#startTimer();
                    });
                });
                this.#observer.observe(this, {
                    subtree: true,
                    characterData: true,
                });
            }

            this.#startTime = performance.now();
            this.#tick();
        }
    }

    /**
     * Stops the auto-dismiss timer.
     */
    #stopTimer() {
        if (this.#animationFrame !== null) {
            cancelAnimationFrame(this.#animationFrame);
            this.#animationFrame = null;
            this.#startTime = null;
        }
        this.#observer?.disconnect();
        this.#observer = null;
    }

    #tick = async () => {
        if (typeof this.#startTime !== "number" || this.#isPaused) {
            return;
        }

        const elapsed = performance.now() - this.#startTime;
        const progress = Math.min(elapsed / this.#duration, 1);

        if (progress < 1) {
            this.#animationFrame = requestAnimationFrame(this.#tick);
        } else {
            await this.#dismiss("timer");
        }
    };

    #handleInteractionIn = (event: PointerEvent) => {
        // Don't pause for touch, since that will pause the timer indefinitely
        if (event.pointerType === "mouse" || event.pointerType === "pen") {
            this.#isPaused = true;
            this.#stopTimer();
        }
    };

    #handleInteractionOut = () => {
        this.#isPaused = false;
        this.#startTimer();
    };

    /** Waits for the toast group to finish transitioning and then resolves. */
    async #waitForGroupTransition() {
        // eslint-disable-next-line @typescript-eslint/consistent-type-assertions
        const root = this.getRootNode() as ShadowRoot;
        const host = root.host;

        if (host instanceof ClgToastGroup) {
            await host.transitionComplete();
        }
    }

    /** @internal */
    handleEvent(e: Event) {
        const { intention } = this.findClosestIntention(e);

        switch (intention) {
            case "DISMISS":
                this.#dismiss("user");
                break;
            case "ICON_SLOTTED":
                if (!this.icon) {
                    this.withIcon = Boolean(this.hasSlotContent("icon"));
                }
                break;
            default:
        }
    }
}

ClgToast.define("clg-toast");

declare global {
    interface HTMLElementTagNameMap {
        "clg-toast": ClgToast;
    }
}
