import {
    CollageElement,
    type PropertyDeclarations,
    type PropertyValues,
} from "collage/web-components/internal/CollageElement";

/**
 * @tagname clg-select-option
 */
export class ClgSelectOption extends CollageElement {
    /** Whether this option is selected */
    declare selected: boolean;
    /** Whether this option can be selected */
    declare disabled: boolean;
    /** The value of this option. If not set, the text content will be used as the value. */
    declare value: string;

    static properties: PropertyDeclarations = {
        selected: { type: Boolean, reflect: true },
        disabled: { type: Boolean, reflect: true },
        value: { reflect: true },
    };

    willUpdate(changed: PropertyValues) {
        super.willUpdate(changed);

        if (typeof this.value === "undefined") {
            this.value = this.textContent?.trim() || "";
        }
    }

    constructor() {
        super();
        this.selected = false;
        this.disabled = false;
    }
}

ClgSelectOption.define("clg-select-option");
declare global {
    interface HTMLElementTagNameMap {
        "clg-select-option": ClgSelectOption;
    }
}
