import {
    CollageElement,
    type PropertyDeclarations,
    type Validators,
    required,
    type PropertyValues,
} from "collage/web-components/internal/CollageElement";
import template from "template!collage/clg-button-group";

/**
 * @tagname clg-button-group
 *
 * @slot - button group content
 */
export class ClgButtonGroup extends CollageElement {
    protected static override template = template;
    protected static validators: Validators = { orientation: required };

    static override properties: PropertyDeclarations = {
        label: { type: String, reflect: true },
        orientation: { type: String, reflect: true },
    };

    /**
     * Sets direction of button group
     * @required
     */
    declare orientation: "horizontal" | "vertical";

    /** Accessible label for the button group */
    declare label?: string;

    constructor() {
        super();
    }

    connectedCallback() {
        super.connectedCallback();

        this.setAttribute("role", "group");
    }

    override update(changed: PropertyValues) {
        super.update(changed);

        if (changed.has("orientation")) {
            this.setAttribute("aria-orientation", this.orientation);
        }

        if (changed.has("label")) {
            if (this.label) {
                this.setAttribute("aria-label", this.label);
            } else {
                this.removeAttribute("aria-label");
            }
        }
    }
}

ClgButtonGroup.define("clg-button-group");

declare global {
    interface HTMLElementTagNameMap {
        "clg-button-group": ClgButtonGroup;
    }
}
