import {
    CollageElement,
    type PropertyDeclarations,
    type Validators,
    required,
} from "collage/web-components/internal/CollageElement";
import template from "template!collage/clg-text-button";
import "collage/web-components/components/loading-spinner/clg-loading-spinner";
import { forwardClicksInTests } from "collage/web-components/internal/forward-clicks-in-tests";
import { LoadingButtonController } from "collage/web-components/reactive-controllers/LoadingButtonController";

/**
 * @tagname clg-text-button
 *
 * @slot - Button content
 * @dependency clg-loading-spinner
 */
export class ClgTextButton extends CollageElement {
    protected static template = template;
    static shadowRootOptions = {
        ...CollageElement.shadowRootOptions,
        delegatesFocus: true,
    };
    protected static validators: Validators = {
        variant: required,
    };

    static override properties: PropertyDeclarations = {
        variant: { type: String, reflect: true },
        underline: { type: Boolean, reflect: true },
        size: { type: String, reflect: true },
        loading: { type: Boolean, reflect: true },
        disabled: { type: Boolean, reflect: true },
        padding: { type: Boolean, reflect: true },
        flush: {
            type: String,
            reflect: true,
        },
        backgroundType: {
            type: String,
            reflect: true,
            attribute: "background-type",
        },
        type: { type: String, reflect: true },
        value: { type: String },
    };

    static delegatedEvents = ["click"];

    /**
     * Visual look of the text button
     * @required
     */
    declare variant: "primary" | "secondary";

    /** Whether or not the text button is underlined */
    declare underline: boolean;

    /** Size of the text button */
    declare size: "base" | "small";

    /** Whether or not the text button is disabled */
    declare disabled: boolean;

    /** Whether or not the text button is loading */
    declare loading: boolean;

    /** The style of background the button is on */
    declare backgroundType: "dynamic" | "light" | "dark";

    /** The button's `type` attribute */
    declare type: "button" | "submit" | "reset";

    /** Whether or not the text button has no padding */
    declare padding: boolean;

    /** The value associated with the button's `name` when it's submitted with form data */
    declare value: string | null;

    /**
     * Align button in a given direction via a negative margin,
     * preserving the full tap target dimensions.
     * */
    declare flush:
        | "top"
        | "right"
        | "bottom"
        | "left"
        | "top right"
        | "top left"
        | "bottom right"
        | "bottom left";

    get #button() {
        return this.renderRoot.querySelector<HTMLElement>(".clg-text-button");
    }

    public click() {
        this.#button?.click();
    }
    public focus(options?: FocusOptions) {
        this.#button?.focus(options);
    }
    public blur() {
        this.#button?.blur();
    }

    constructor() {
        super();
        this.type = "button";
        this.underline = false;
        this.size = "base";
        this.padding = false;
        this.disabled = false;

        new LoadingButtonController(this, () => this.#button);
        forwardClicksInTests(this, () => this.#button);
    }
}

ClgTextButton.define("clg-text-button");

declare global {
    interface HTMLElementTagNameMap {
        "clg-text-button": ClgTextButton;
    }
}
