import type {
    PropertyDeclarations,
    PropertyValues,
    ReactiveElement,
} from "@lit/reactive-element";
import {
    changeHtmlTag,
    toggleStringAttribute,
} from "collage/web-components/internal/html";

// eslint-disable-next-line @typescript-eslint/no-explicit-any
type Constructor<T = object> = abstract new (...args: any[]) => T;

export interface AnchorOrButtonInterface {
    disabled: boolean;
    type: "button" | "submit" | "reset";
    target?: "_self" | "_blank" | "_parent" | "_top" | "unfencedTop";
    rel?: string;
    href?: string;
}

/**
 * Adds properties and logic to switch between rendering an anchor or button element
 */
export const AnchorOrButtonMixin = <T extends Constructor<ReactiveElement>>(
    superClass: T
) => {
    abstract class AnchorOrButtonMixinClass
        extends superClass
        implements AnchorOrButtonInterface
    {
        /** Whether or not the element is interactive */
        declare disabled: boolean;
        /** The button's `type` attribute */
        declare type: "button" | "submit" | "reset";

        /** Where to display the linked URL */
        declare target?: "_self" | "_blank" | "_parent" | "_top" | "unfencedTop";
        /** The relationship of the linked URL as space-separated link types. */
        declare rel?: string;
        /** The URL that the hyperlink points to. */
        declare href?: string;

        static properties: PropertyDeclarations = {
            disabled: { type: Boolean, reflect: true },
            type: { type: String },
            target: {},
            href: {},
            rel: {},
        };

        // Needed to satisfy TS
        // eslint-disable-next-line @typescript-eslint/no-explicit-any
        constructor(..._args: any[]) {
            super();
            this.type = "button";
            this.disabled = false;
        }

        protected get _button(): HTMLElement | null {
            throw new Error("This must be redefined to return the target element.");
        }

        override update(changed: PropertyValues) {
            super.update(changed);

            if (!this._button) return;

            if (this.href && this._button.tagName.toLowerCase() === "button") {
                changeHtmlTag(this._button, "a");
            }
            if (!this.href && this._button.tagName.toLowerCase() === "a") {
                changeHtmlTag(this._button, "button");
            }

            const btn = this._button;
            if (this.href) {
                // Remove button attrs
                btn.removeAttribute("type");
                btn.removeAttribute("disabled");
                // Add anchor attrs
                toggleStringAttribute(btn, "target", this.target);
                toggleStringAttribute(btn, "rel", this.rel);
                if (this.disabled) {
                    btn.removeAttribute("href");
                    btn.setAttribute("role", "link");
                    btn.setAttribute("aria-disabled", "true");
                } else {
                    btn.setAttribute("href", this.href);
                    btn.removeAttribute("role");
                    btn.removeAttribute("aria-disabled");
                }
            } else {
                btn.removeAttribute("href");
                btn.removeAttribute("rel");
                btn.removeAttribute("target");
                btn.removeAttribute("role");
                btn.removeAttribute("aria-disabled");
                btn.setAttribute("type", this.type);
                btn.toggleAttribute("disabled", this.disabled);
            }
        }
    }

    // eslint-disable-next-line @typescript-eslint/consistent-type-assertions
    return AnchorOrButtonMixinClass as Constructor<AnchorOrButtonInterface> & T;
};
