import type { Placement } from "@floating-ui/dom";

export interface ClgRepositionEventDetail {
    placement: Placement;
}

/** Emitted after the floating panel position is recomputed. */
export class ClgRepositionEvent extends Event {
    readonly detail: ClgRepositionEventDetail;

    constructor(detail: ClgRepositionEventDetail) {
        super("clg-reposition", {
            bubbles: true,
            cancelable: false,
            composed: true,
        });
        this.detail = detail;
    }
}

declare global {
    interface GlobalEventHandlersEventMap {
        "clg-reposition": ClgRepositionEvent;
    }
}
