/** Emitted after the element is opened and applicable animations have completed. */
export class ClgOpenEvent extends Event {
    constructor() {
        super("clg-open", { bubbles: true, cancelable: false, composed: true });
    }
}

interface ClgCloseEventDetails {
    origin?: "user" | "internal";
}

/**
 * Emitted when the element is closed and applicable animations have completed.
 * Event is only cancellable when triggered by a user-action. See event.details.origin
 * to check.
 */
export class ClgCloseEvent extends Event {
    readonly detail: ClgCloseEventDetails;

    constructor(detail: ClgCloseEventDetails, options: EventInit = {}) {
        super("clg-close", {
            bubbles: true,
            cancelable: false,
            composed: true,
            ...options,
        });
        this.detail = detail;
    }
}

declare global {
    interface GlobalEventHandlersEventMap {
        "clg-open": ClgOpenEvent;
        "clg-close": ClgCloseEvent;
    }
}
