import {
    CollageElement,
    type PropertyDeclarations,
    type Validators,
    required,
} from "collage/web-components/internal/CollageElement";
import template from "template!collage/clg-icon-button";
import { forwardClicksInTests } from "collage/web-components/internal/forward-clicks-in-tests";

/**
 * @tagname clg-icon-button
 *
 * @slot - The icon to display in the button
 */
export class ClgIconButton extends CollageElement {
    protected static override template = template;
    static shadowRootOptions = {
        ...CollageElement.shadowRootOptions,
        delegatesFocus: true,
    };
    protected static validators: Validators = {
        variant: required,
    };

    static override properties: PropertyDeclarations = {
        label: {},
        variant: { type: String, reflect: true },
        size: { type: String, reflect: true },
        disabled: { type: Boolean, reflect: true },
        backgroundType: {
            type: String,
            reflect: true,
            attribute: "background-type",
        },
    };

    /** Label that describes the button's action */
    declare label: string;

    /**
     * Visual look of the button
     * @required
     */
    declare variant:
        | "primary"
        | "secondary-strong"
        | "secondary-subtle"
        | "tertiary"
        | "transparent";

    /** Size of the button */
    declare size: "base" | "small" | "smallest";

    /** If true, the button will be disabled */
    declare disabled: boolean;

    /** The style of background the button is on */
    declare backgroundType: "dynamic" | "light" | "dark";

    get #button() {
        return this.renderRoot.querySelector<HTMLElement>(".clg-icon-button");
    }

    constructor() {
        super();
        this.size = "base";
        this.disabled = false;
        this.backgroundType = "dynamic";

        forwardClicksInTests(this, () => this.#button);
    }
}

ClgIconButton.define("clg-icon-button");

declare global {
    interface HTMLElementTagNameMap {
        "clg-icon-button": ClgIconButton;
    }
}
