import {
    CollageElement,
    type PropertyDeclarations,
} from "collage/web-components/internal/CollageElement";
import template from "template!collage/clg-shop-avatar";
import "collage/web-components/components/icon/clg-icon";

/**
 * @tagname clg-shop-avatar
 *
 * @dependency clg-icon
 *
 * @slot - The shop image. If none is provided, a fallback icon will be shown.
 */
export class ClgShopAvatar extends CollageElement {
    protected static template = template;

    /**
     * Size variant for the shop avatar.
     */
    declare size: "smaller" | "base" | "larger" | "largest";

    /**
     * Whether the shop avatar has a border.
     */
    declare border: boolean;

    static override properties: PropertyDeclarations = {
        size: { type: String, reflect: true },
        border: { type: Boolean, reflect: true },
    };

    constructor() {
        super();
        this.size = "base";
        this.border = false;
    }
}

ClgShopAvatar.define("clg-shop-avatar");

declare global {
    interface HTMLElementTagNameMap {
        "clg-shop-avatar": ClgShopAvatar;
    }
}
