import CollageElement, {
    type PropertyDeclarations,
    type PropertyValues,
    type Validators,
    required,
} from "collage/web-components/internal/CollageElement";
import template from "template!collage/clg-text-link";
import { forwardClicksInTests } from "collage/web-components/internal/forward-clicks-in-tests";

/**
 * @tagname clg-text-link
 *
 * @slot - The link's text content.
 * @slot icon - The icon placed next to the text.
 */
export class ClgTextLink extends CollageElement {
    protected static template = template;
    static shadowRootOptions = {
        ...CollageElement.shadowRootOptions,
        delegatesFocus: true,
    };
    static validators: Validators = { href: required };

    /** Where to display the linked URL */
    declare target?: "_self" | "_blank" | "_parent" | "_top" | "unfencedTop";
    /** The relationship of the linked URL as space-separated link types. */
    declare rel?: string;
    /**
     * The URL that the hyperlink points to.
     * @required
     */
    declare href: string;
    /** If true, clicking the link will not direct to the provided href. */
    declare disabled: boolean;
    /** If true, the underline will be hidden. The underline will also be hidden if an icon is slotted. */
    declare noUnderline: boolean;
    /** Sets the position of the icon relative to the text. */
    declare icon: "start" | "end" | false;

    static override properties: PropertyDeclarations = {
        target: {},
        href: {},
        rel: {},
        disabled: { type: Boolean, reflect: true },
        noUnderline: {
            type: Boolean,
            reflect: true,
            attribute: "no-underline",
        },
        icon: {
            type: String,
            reflect: true,
            converter: {
                toAttribute(value) {
                    // Don't add attribute if `false`
                    return value ? value : null;
                },
                fromAttribute(value) {
                    return value === "false" ? false : value;
                },
            },
        },
    };

    static delegatedEvents = ["click", "slotchange"];

    constructor() {
        super();
        this.disabled = false;
        this.noUnderline = false;
        this.icon = false;

        forwardClicksInTests(this, () => this.#anchor);
    }

    get #anchor() {
        return this.renderRoot.querySelector("a");
    }

    override willUpdate(changed: PropertyValues) {
        super.willUpdate(changed);

        if (this.hasSlotContent("icon") && !this.icon) {
            this.icon = "start";
        }
        if (!this.hasSlotContent("icon") && this.icon) {
            this.icon = false;
        }
    }

    override update(changed: PropertyValues) {
        super.update(changed);

        const anchor = this.#anchor;
        if (!anchor) return;

        if (this.disabled) {
            anchor.removeAttribute("href");
            anchor.setAttribute("role", "link");
            anchor.setAttribute("aria-disabled", "true");
        } else {
            anchor.setAttribute("href", this.href);
            anchor.removeAttribute("role");
            anchor.removeAttribute("aria-disabled");
        }
    }

    handleEvent(event: Event) {
        const { intention } = this.findClosestIntention(event);

        if (intention === "ICON_CHANGE") {
            if (this.hasSlotContent("icon")) {
                this.icon = this.icon || "start";
            } else {
                this.icon = false;
            }
        }

        if (intention === "CLICK" && this.disabled) {
            event.preventDefault();
            event.stopImmediatePropagation();
        }
    }
}

ClgTextLink.define("clg-text-link");

declare global {
    interface HTMLElementTagNameMap {
        "clg-text-link": ClgTextLink;
    }
}
