import {
    CollageFormElement,
    type PropertyValues,
    type PropertyDeclarations,
    type Validators,
    required,
    hasContent,
} from "collage/web-components/internal/CollageFormElement";
import template from "template!collage/clg-text-input";
import size from "util/size";
import {
    characterCountMsg,
    maxLengthExceededErrorMsg,
} from "collage/web-components/internal/translations";
import { submitOnEnter } from "collage/web-components/internal/submit-on-enter";

const DESCRIBEDBY_IDS = {
    ERROR: "error-message",
    CHARACTER_COUNT: "character-count-screen-reader",
    CAPTION: "caption",
    HELPER: "helper-text",
};

/**
 * Base class for textbox elements (e.g., <input> and <textarea>)
 *
 * @tagname clg-input
 *
 * @slot label - Accessible label of the input
 * @slot iconbefore - Prepended icon in the text input
 * @slot iconafter - Appended icon in the text input
 * @slot helper-text - Additional instructions or context for the text field
 * @slot caption - Additional instructions or context for the text field
 *
 * @fires {Event} input - Fires when the user types into the input
 * @fires {Event} change - Fires when the input value changes
 * @fires {FocusEvent} focus - Fires when the input gains focus
 * @fires {FocusEvent} blur - Fires when the input loses focus
 *
 * @attr {string} defaultValue - Sets the initial value (only needed in Preact).
 */
export abstract class CollageTextFieldElement extends CollageFormElement {
    protected static template = template;
    static shadowRootOptions = {
        ...CollageFormElement.shadowRootOptions,
        delegatesFocus: true,
    };

    protected abstract get textBox(): HTMLInputElement | HTMLTextAreaElement;

    protected static validators: Validators = {
        label: { property: required, slot: hasContent },
    };

    /** Accessible label of the input */
    declare label: string;
    /** For SSR support with slots, sets whether the iconbefore slot is occupied */
    declare withIconBefore: boolean;
    /** For SSR support with slots, sets whether the iconafter slot is occupied */
    declare withIconAfter: boolean;
    /** The value of the form field. */
    declare value: string;
    /** If true, a character counter will be display below the text field. */
    declare showCharacterCount: boolean;
    /** Sets if the form field is required */
    declare required: boolean;
    /** Sets if the form field is optional */
    declare optional: boolean;
    /** Renders the provided text before the input to add context for the user. */
    declare prefixText: string;
    /** Renders the provided text after the input to add context for the user. */
    declare suffix: string;
    /** Sets the text displayed in the form field when it has no value. */
    declare placeholder: string;
    /** Sets this component's size for usage in base or compact UI designs. */
    declare size: "small" | "base";
    /** The style of background the element is on */
    declare backgroundType: "dynamic" | "dark" | "light";
    /** If true, the form field will display errors to the user prior to form submission. */
    declare validateOnChange: boolean;

    /** The maximum number of characters allowed to be typed into the form field */
    declare maxLength: number;
    /** The minimum number of characters allowed to be typed into the form field */
    declare minLength: number;

    /**
     * Provides a hint to the user agent specifying how to, or indeed whether to, prefill a form control.
     * @see [MDN](https://developer.mozilla.org/en-US/docs/Web/HTML/Reference/Attributes/autocomplete)
     */
    declare autocomplete: string;

    /**
     * Controls whether inputted text is automatically capitalized and, if so, in what manner
     * @see [MDN](https://developer.mozilla.org/en-US/docs/Web/HTML/Reference/Global_attributes/autocapitalize)
     */
    declare autocapitalize:
        | "off"
        | "none"
        | "on"
        | "sentences"
        | "words"
        | "characters";

    /**
     * Controls whether autocorrection of editable text is enabled for spelling and/or punctuation errors.
     * @see [MDN](https://developer.mozilla.org/en-US/docs/Web/HTML/Reference/Global_attributes/autocorrect)
     */
    declare autocorrect: boolean;

    /**
     * Sets whether the input field will be focused on page load.
     */
    declare autofocus: boolean;

    /**
     * Defines what action label (or icon) to present for the enter key on virtual keyboards.
     * @see [MDN](https://developer.mozilla.org/en-US/docs/Web/HTML/Reference/Global_attributes/enterkeyhint)
     */
    declare enterKeyHint:
        | "enter"
        | "done"
        | "go"
        | "next"
        | "previous"
        | "search"
        | "send";

    static override properties: PropertyDeclarations = {
        autocapitalize: { type: String },
        autocomplete: { type: String, reflect: true },
        autocorrect: { type: String, reflect: true },
        autofocus: { type: Boolean, reflect: true },
        disabled: { type: Boolean, reflect: true },
        // matches global DOM attribute
        // eslint-disable-next-line etsy-rules/lit-attribute-names
        enterKeyHint: { type: String, attribute: "enterkeyhint" },
        label: { type: String },
        // matches <input> DOM attribute
        // eslint-disable-next-line etsy-rules/lit-attribute-names
        maxLength: { type: Number, reflect: true, attribute: "maxlength" },
        // matches <input> DOM attribute
        // eslint-disable-next-line etsy-rules/lit-attribute-names
        minLength: { type: Number, reflect: true, attribute: "minlength" },
        name: { type: String, reflect: true },
        optional: { type: Boolean, reflect: true },
        placeholder: { type: String, reflect: true },
        // "prefix" is already an Element property
        // eslint-disable-next-line etsy-rules/lit-attribute-names
        prefixText: { type: String, attribute: "prefix" },
        required: { type: Boolean, reflect: true },
        size: { type: String, reflect: true },
        suffix: { type: String },
        value: { type: String },
        backgroundType: {
            type: String,
            reflect: true,
            attribute: "background-type",
        },
        withIconBefore: {
            type: Boolean,
            reflect: true,
            attribute: "with-icon-before",
        },
        withIconAfter: {
            type: Boolean,
            reflect: true,
            attribute: "with-icon-after",
        },
        spellcheck: {
            type: Boolean,
            converter: {
                fromAttribute: (value) =>
                    !value || value === "false" ? false : true,
                toAttribute: (value) => (value ? "true" : "false"),
            },
        },
        showCharacterCount: {
            type: Boolean,
            reflect: true,
            attribute: "show-character-count",
        },
        validateOnChange: { type: Boolean, attribute: "validate-on-change" },
    };

    static delegatedEvents = [
        "change",
        "input",
        "click",
        "slotchange",
        "change",
        "pointerdown",
    ];

    constructor() {
        super();
        this.disabled = false;
        this.showCharacterCount = false;
        this.optional = false;
        this.placeholder = "";
        this.prefixText = "";
        this.required = false;
        this.size = "base";
        this.suffix = "";
        this.value = "";
        this.withIconAfter = false;
        this.withIconBefore = false;
    }

    protected override firstUpdated(changed: PropertyValues): void {
        super.firstUpdated(changed);

        // Fixes the typing of the event listeners
        // eslint-disable-next-line @typescript-eslint/consistent-type-assertions
        const textBox = this.textBox as HTMLInputElement;

        // Focus and blur events don't bubble to the shadow root,
        // so adding them manually in lieu of delegatedEvents
        textBox.addEventListener("focus", this.#handleFocus);
        textBox.addEventListener("blur", this.#handleBlur);
        textBox.addEventListener("keydown", this.#handleKeyDown);

        this.onDisconnect(() => {
            textBox?.removeEventListener("focus", this.#handleFocus);
            textBox?.removeEventListener("blur", this.#handleBlur);
            textBox?.removeEventListener("keydown", this.#handleKeyDown);
        });
    }

    protected override willUpdate(changed: PropertyValues) {
        super.willUpdate(changed);

        // Only run on first update
        // Normally, we'd use the "value" attribute for the initial form value.
        // But Preact might strip out the value attribute and just set the property on the element.
        // So this workaround for supporting `defaultValue` is here for Preact.
        if (!this.hasUpdated && this.hasAttribute("defaultvalue") && !this.value) {
            this.value = this.getAttribute("defaultvalue") || "";
        }

        // We call validate in `willUpdate` and `updated`
        // If the textBox validity changes, we can only detect that after a render (in `updated`)
        // If not, all other factors into the validity should still be accurate here. It's
        // the difference of only this render running, or 1-2 more renders if we wait until `updated`.
        this.validate();
    }

    protected override update(changed: PropertyValues) {
        super.update(changed);

        // Value changes
        if (changed.has("value")) {
            this.internals.setFormValue(this.value);
            // eslint-disable-next-line @typescript-eslint/no-non-null-assertion
            const input = this.textBox!;
            if (input.value !== this.value) {
                input.value = this.value;
            }
        }

        if (changed.has("showCharacterCount") || changed.has("value")) {
            this.#updateCharacterCount();
        }

        this.#updateDescribedByIds();
    }

    protected override updated(changed: PropertyValues) {
        super.updated(changed);

        this.updateComplete.then(() => this.validate());
    }

    protected formResetCallback() {
        super.formResetCallback();
        this.value =
            this.getAttribute("defaultValue") || this.getAttribute("value") || "";
    }

    protected formStateRestoreCallback(state: string | File | FormData) {
        // eslint-disable-next-line @typescript-eslint/consistent-type-assertions
        this.value = state as string;
    }

    protected getValidity() {
        const hasCustomValidity = this.customValidityMessage.length > 0;

        const exceedsMaxLength =
            this.maxLength > 0 && this.value.length > this.maxLength;

        // If `setCustomValidity` is used, the input will always be invalid
        // until they explicitly clear it with `setCustomValidity("")`. This
        // matches the behavior of `HTMLInputElement.setCustomValidity()`
        if (
            !exceedsMaxLength &&
            !hasCustomValidity &&
            this.textBox.validity.valid
        ) {
            if (!this.error) {
                // Preserve invalid state if error property is used
                this.invalid = false;
                this.validationMessage = "";
            }
            return { flags: {} };
        }

        const validationMessage = hasCustomValidity
            ? this.getCustomValidity()
            : exceedsMaxLength
            ? maxLengthExceededErrorMsg({
                  count: this.value.length,
                  total: this.maxLength,
              })
            : this.textBox.validationMessage;
        const flags: ValidityStateFlags = {
            badInput: this.textBox.validity.badInput,
            customError: hasCustomValidity,
            patternMismatch: this.textBox.validity.patternMismatch,
            rangeOverflow: this.textBox.validity.rangeOverflow,
            rangeUnderflow: this.textBox.validity.rangeUnderflow,
            stepMismatch: this.textBox.validity.stepMismatch,
            tooLong: exceedsMaxLength,
            tooShort: this.textBox.validity.tooShort,
            typeMismatch: this.textBox.validity.typeMismatch,
            valueMissing: this.textBox.validity.valueMissing,
        };

        if (!this.error) {
            // Preserve invalid state if error property is used
            // Don't show error state if not touched
            this.invalid = this.touched;
            this.validationMessage = validationMessage;
        }

        return { flags, message: validationMessage, anchor: this.textBox };
    }

    /** Sets focus to the text field. */
    public focus(options?: FocusOptions) {
        if (!this.textBox || this.isUpdatePending) {
            this.updateComplete.then(() => {
                this.textBox.focus(options);
            });
        } else {
            this.textBox.focus(options);
        }
    }

    /** Removes focus from the text field. */
    public blur() {
        this.textBox.blur();
    }

    /** Selects all text in the text field. */
    public select() {
        this.textBox.select();
    }

    /** Sets the start and end positions of the current text selection in the text field. */
    public setSelectionRange(
        start: number,
        end: number,
        direction: "forward" | "backward" | "none" = "none"
    ) {
        this.textBox.setSelectionRange(start, end, direction);
    }

    /** Replaces a range of text in the text field with a new string. */
    public setRangeText(
        replacement: string,
        start?: number,
        end?: number,
        selectMode?: "select" | "start" | "end" | "preserve"
    ) {
        this.textBox.setRangeText(
            replacement,
            // eslint-disable-next-line @typescript-eslint/no-non-null-assertion
            start ?? this.textBox.selectionStart!,
            // eslint-disable-next-line @typescript-eslint/no-non-null-assertion
            end ?? this.textBox.selectionEnd!,
            selectMode
        );
        this.value = this.textBox.value;
    }

    /** The start position of the current text selection */
    public get selectionStart(): number | null {
        return this.textBox?.selectionStart ?? null;
    }
    public set selectionStart(value: number | null) {
        if (this.textBox) {
            this.textBox.selectionStart = value;
        }
    }

    /** The end position of the current text selection */
    public get selectionEnd(): number | null {
        return this.textBox?.selectionEnd ?? null;
    }
    public set selectionEnd(value: number | null) {
        if (this.textBox) {
            this.textBox.selectionEnd = value;
        }
    }

    #updateDescribedByIds() {
        const ids: string[] = [];

        if (this.invalid) {
            ids.push(DESCRIBEDBY_IDS.ERROR);
        }
        if (this.showCharacterCount) {
            ids.push(DESCRIBEDBY_IDS.CHARACTER_COUNT);
        }
        if (this.withCaption) {
            ids.push(DESCRIBEDBY_IDS.CAPTION);
        }
        if (this.withHelperText) {
            ids.push(DESCRIBEDBY_IDS.HELPER);
        }

        if (ids.length > 0) {
            this.textBox.setAttribute("aria-describedby", ids.join(" "));
        } else {
            this.textBox.removeAttribute("aria-describedby");
        }
    }

    #handleFocus = () => {
        this.dispatchEvent(
            new FocusEvent("focus", {
                bubbles: true,
                cancelable: false,
                composed: true,
            })
        );
    };
    #handleBlur = () => {
        if (this.validateOnChange && this.required && this.value.length === 0) {
            // Normally the required state doesn't trigger an error unless the user adds
            // some text to the field. To get validateOnChange to play with required,
            // we'll manually cause the field to validate.
            this.touched = true;
            this.requestUpdate();
        }

        this.dispatchEvent(
            new FocusEvent("blur", {
                bubbles: true,
                cancelable: false,
                composed: true,
            })
        );
    };
    #handleKeyDown = (e: KeyboardEvent) => {
        submitOnEnter(e, this);
    };

    /** @internal */
    handleEvent(e: Event) {
        const { intention, target } = this.findClosestIntention(e);

        switch (intention) {
            case "INPUT":
                if (
                    !(target instanceof HTMLInputElement) &&
                    !(target instanceof HTMLTextAreaElement)
                )
                    return;
                if (this.validateOnChange) {
                    this.touched = true;
                }
                this.value = target.value;
                break;
            case "ICON_SLOT_CHANGE":
                this.withIconBefore = this.hasSlotContent("iconbefore");
                this.withIconAfter = this.hasSlotContent("iconafter");
                break;
            case "INPUT_CHANGE":
                this.dispatchEvent(
                    new Event("change", {
                        composed: true,
                        bubbles: true,
                        cancelable: false,
                    })
                );
                break;
            case "BOX_CLICK":
                this.#handleVisualBoxPointerDown(e);
                break;
            default:
        }
    }

    #handleVisualBoxPointerDown(event: Event) {
        // eslint-disable-next-line @typescript-eslint/consistent-type-assertions
        const target = event.target as HTMLElement;
        const isBox = target?.id === "visual-box";
        const isSlot = target.hasAttribute("slot");

        if (isBox || isSlot) {
            event.preventDefault();
            this.textBox.focus();
        }
    }

    #updateCharacterCount() {
        const characterCountRoot =
            this.shadowRoot?.querySelector("#character-count");
        const visibleCharacterCount = characterCountRoot?.querySelector(
            "#character-count-visible"
        );
        const screenReaderCharacterCount = characterCountRoot?.querySelector(
            "#character-count-screen-reader"
        );

        if (
            !characterCountRoot ||
            !visibleCharacterCount ||
            !screenReaderCharacterCount
        ) {
            return;
        }

        if (!this.showCharacterCount || !this.maxLength) {
            characterCountRoot.toggleAttribute("hidden", true);
            return;
        }

        const characterCount = `${size(this.value) || 0}`;

        visibleCharacterCount.textContent = `${characterCount}/${this.maxLength}`;
        screenReaderCharacterCount.textContent = characterCountMsg({
            count: characterCount,
            total: this.maxLength,
        });
        characterCountRoot.removeAttribute("hidden");
    }
}
