import { CollageElement } from "collage/web-components/internal/CollageElement";
import { type ClgToast } from "collage/web-components/components/toast/clg-toast";
import {
    AnimationController,
    type ClgTransitionAnimation,
} from "collage/web-components/reactive-controllers/AnimationController";
import template from "template!collage/clg-toast-group";
import { type ClgTransitionEndEvent } from "collage/web-components/events/transition";

/**
 * @tagname clg-toast-group
 *
 * @slot - clg-toast elements
 */
export class ClgToastGroup extends CollageElement {
    static template = template;

    static instance: ClgToastGroup | null = null;

    static transitionAnimation: ClgTransitionAnimation;

    #animationController!: AnimationController;

    connectedCallback() {
        super.connectedCallback();

        if (!ClgToastGroup.transitionAnimation) {
            const computedStyle = window.getComputedStyle(this);
            const easingIn = computedStyle.getPropertyValue(
                "--clg-effect-pal-curve-long-in"
            );
            const easingOut = computedStyle.getPropertyValue(
                "--clg-effect-pal-curve-long-out"
            );
            const durationIn = parseInt(
                computedStyle.getPropertyValue("--clg-effect-pal-duration-300"),
                10
            );
            const durationOut = parseInt(
                computedStyle.getPropertyValue("--clg-effect-pal-duration-200"),
                10
            );
            ClgToastGroup.transitionAnimation = {
                enter: {
                    keyframes: [{ translate: "0 100%" }, { translate: "0 0" }],
                    //  clg.effect.pal.curve.longIn
                    easing: easingIn,
                    // clg.effect.pal.duration.300
                    duration: durationIn,
                },
                exit: {
                    keyframes: [
                        { translate: "0 0" },
                        { opacity: 0.5, offset: 0.3 },
                        { translate: "0 100%", opacity: 0 },
                    ],
                    //  clg.effect.pal.curve.longOut
                    easing: easingOut,
                    // clg.effect.pal.duration.200
                    duration: durationOut,
                },
            };
        }

        this.#animationController = new AnimationController(this, {
            transitionAnimation: ClgToastGroup.transitionAnimation,
        });

        this.addEventListener("clg-transition-end", this.#handleTransitionEnd);

        // eslint-disable-next-line @typescript-eslint/consistent-type-assertions
        const ctor = this.constructor as typeof ClgToastGroup;
        ctor.instance = this;
    }

    disconnectedCallback() {
        super.disconnectedCallback();
        this.removeEventListener("clg-transition-end", this.#handleTransitionEnd);
        // eslint-disable-next-line @typescript-eslint/consistent-type-assertions
        const ctor = this.constructor as typeof ClgToastGroup;
        ctor.instance = null;
    }

    transitionComplete() {
        return this.#animationController.transitionComplete();
    }

    #handleTransitionEnd(event: ClgTransitionEndEvent) {
        if (event.target === this && this.children.length === 0) {
            this.remove();
        }
    }

    /**
     * Queues a toast for display in the group, ensuring all animations are uninterrupted.
     */
    public async queue(toast: ClgToast) {
        await this.updateComplete;
        await this.#animationController.transitionComplete();

        // Rendering the toast first in a temporary div so that
        // its own shadow DOM can be created BEFORE insertion into the
        // toast group. This is done so that the Toast has its shadow DOM contents,
        // and therefore its dimensions, settled, which makes the entrance
        // transitions smooth. Otherwise the math run to create the transitions
        // isn't accurate and there's a bit of jumping as the elements sort
        // themselves out.
        const tempDiv = document.createElement("div");
        tempDiv.style.display = "none";
        tempDiv.append(toast);
        document.body.append(tempDiv);
        await toast.updateComplete;

        this.prepend(toast);
        tempDiv.remove();
    }

    /** Removes all elements from the toast stack and turns when the remove transition finishes. */
    async empty() {
        await this.transitionComplete();
        this.innerHTML = "";
        await this.transitionComplete();
    }
}

ClgToastGroup.define("clg-toast-group");

declare global {
    interface HTMLElementTagNameMap {
        "clg-toast-group": ClgToastGroup;
    }
}
