/** Emitted when a custom transition finishes. */
export class ClgTransitionEndEvent extends Event {
    constructor() {
        super("clg-transition-end", {
            bubbles: true,
            cancelable: false,
            composed: true,
        });
    }
}

declare global {
    interface GlobalEventHandlersEventMap {
        "clg-transition-end": ClgTransitionEndEvent;
    }
}
