import {
    CollageElement,
    type PropertyDeclarations,
    type Validators,
    required,
} from "collage/web-components/internal/CollageElement";
import template from "template!collage/clg-ad-signal";

/**
 * @tagname clg-ad-signal
 *
 */
export class ClgAdSignal extends CollageElement {
    protected static template = template;

    /**
     * How strongly the signal should appear
     * @required
     */
    declare variant: "strong" | "subtle";
    /** Toggles the size modifier to increase the indicator size */
    declare size: "base" | "large";

    static override properties: PropertyDeclarations = {
        variant: { type: String, reflect: true },
        size: { type: String, reflect: true },
    };

    protected static validators: Validators = {
        variant: required,
    };

    constructor() {
        super();
        this.size = "base";
    }
}

ClgAdSignal.define("clg-ad-signal");

declare global {
    interface HTMLElementTagNameMap {
        "clg-ad-signal": ClgAdSignal;
    }
}
