import transform, { type Transformer } from "translator/mini-mustache/transform";
import type { TTree } from "translator/mini-mustache/types";

export interface TemplateData {
    [key: string]: boolean | number | string | null | undefined;
}

const toStringTransformer: Transformer<string, string, string, TemplateData> = {
    visitTree: (children, _data) => children.join(""),
    visitBlock: (variable, children, data) =>
        data[variable] ? children.join("") : "",
    visitVariable: (variable, data) => {
        const value = data[variable];
        const truthy = value || value === 0;
        return truthy ? value.toString() : "";
    },
};

export default function renderToString(tree: TTree, data: TemplateData): string {
    return transform(tree, toStringTransformer, data);
}
