/* eslint-disable react/jsx-filename-extension */
import etsyMsg from "common/etsy.msg";
import parse from "translator/mini-mustache/parse";
import renderToPreact from "translator/mini-mustache/render/to-preact";
import renderToString, {
    type TemplateData,
} from "translator/mini-mustache/render/to-string";
import type { TTree } from "translator/mini-mustache/types";
import type {
    TemplateArgs,
    TemplateToComponent,
    PluralTemplateToComponent,
} from "translator/preact/types";

/**
 * Translate a string: returns the translated string. If you need to use
 * substitutions or interactive Preact elements then use `buildMsg()` instead.
 * Use `buildPluralMsg()` if you need pluralization.
 *
 *     const greeting = msg({
 *         content: "Hello world!",
 *         desc: "A greeting for our website",
 *     });
 *     greeting; // => "Hello world!"
 *
 */
export function msg({ content }: { content: string; desc: string; proj?: string }) {
    return content;
}

interface BuildMsgArgs {
    content: string;
    desc: string;
    proj?: string;
}

interface BuildMsgReturn {
    (data?: TemplateData): string;
    toComponent: () => TemplateToComponent;
}

interface BuildPluralMsgReturn {
    (pluralCount: number, data?: TemplateData): string;
    toComponent: () => PluralTemplateToComponent;
}

/**
 * Declare a translatable message. Returns a function that will return a string
 * of the translated content when called; an optional object of key-value pairs
 * can be passed to be formatted into the translation:
 *
 *     const greeting = buildMsg({
 *         content: "Hello, {{name}}!",
 *         desc: "A greeting for the user",
 *     });
 *     greeting(); // => "Hello, !"
 *     greeting({ name: "World" }); // => "Hello, World!"
 *
 * You can call `toComponent()` on the returned function to get a renderable
 * Preact component.
 *
 * Note that the `content` and `desc` combined identify the message, so
 * changing either will change the message's identity: this can cause it to be
 * rendered untranslated until new translations are completed.
 */
export function buildMsg({ content }: BuildMsgArgs) {
    let tree: TTree | undefined = undefined;
    // Lazily parse and memoize the translation.
    const getTree = () => {
        if (tree === undefined) {
            tree = parse(content);
        }
        return tree;
    };

    const translate: BuildMsgReturn = (data?: TemplateData) => {
        return data === undefined ? content : renderToString(getTree(), data);
    };

    /**
     * Returns a Preact component to render the translation.
     *
     *     const Greeting = buildMsg({ ... }).toComponent();
     *     <span><Greeting args={{ name: "World" }} /></span>; // => <span>Hello, World!</span>
     *
     */
    translate.toComponent = (): TemplateToComponent =>
        function Msg({ args }) {
            return renderToPreact(getTree(), args ?? {});
        };

    return translate;
}

interface BuildPluralMsgArgs {
    content: {
        one: string;
        many: string;
    };
    desc: string;
    proj?: string;
}

// The shape of the translated JSON files written by
// Etsy\Modules\BuildaPackDependencies\CLI\Build\WriteJavascriptNativemsgs.
interface BuildapackPluralMsgArgs {
    content: [string[], unknown[]];
}

/**
 * Declare a plural translatable message. Returns a function that takes a
 * plural count as its first argument (and optional second argument of
 * key-value pairs for formatting); it will return the translated content in
 * the correct plural case for the current language.
 *
 * `toComponent` can be called on the returned function to get a Preact
 * component. That component requires a `pluralCount` prop in order to be able
 * to pick the correct plural translation.
 */
export function buildPluralMsg(args: BuildPluralMsgArgs) {
    // Users can only pass in BuildPluralMsgArgs themselves, but after Buildapack transformation
    // we can also receive translated contents which have a different shape.
    // eslint-disable-next-line @typescript-eslint/consistent-type-assertions
    const realArgs = args as BuildPluralMsgArgs | BuildapackPluralMsgArgs;

    const trees: Map<string, TTree> = new Map();
    // Lazily parse and memoize translations.
    const getTree = (content: string) => {
        let tree = trees.get(content);
        if (tree === undefined) {
            tree = parse(content);
            trees.set(content, tree);
        }
        return tree;
    };

    const translate: BuildPluralMsgReturn = (
        pluralCount: number,
        data?: TemplateData
    ) => {
        const translation = pickPluralCase(realArgs, pluralCount);
        return data === undefined
            ? translation
            : renderToString(getTree(translation), data);
    };

    /**
     * Returns a Preact component to render the translation.
     *
     *     const Greeting = buildPluralMsg({ ... }).toComponent();
     *     <Greeting pluralCount={2} args={{ count: 2 }} /> // => "2 widgets"
     *
     */
    translate.toComponent = (): PluralTemplateToComponent => {
        const Msg = ({
            pluralCount,
            args: msgArgs,
        }: {
            pluralCount: number;
            args?: TemplateArgs;
        }) => {
            const translation = pickPluralCase(realArgs, pluralCount);
            return renderToPreact(getTree(translation), msgArgs ?? {});
        };
        Msg.displayName = "Msg";
        return Msg;
    };

    return translate;
}

function pickPluralCase(
    args: BuildPluralMsgArgs | BuildapackPluralMsgArgs,
    pluralCount: number
): string {
    if (isSourcePlural(args)) {
        return pluralCount === 1 ? args.content.one : args.content.many;
    }
    const [content, pluralForms] = args.content;
    return etsyMsg.pickPluralCase(content, pluralForms, pluralCount);
}

/** Detects whether or not we're getting the source content (rather than translations). */
function isSourcePlural(
    args: BuildPluralMsgArgs | BuildapackPluralMsgArgs
): args is BuildPluralMsgArgs {
    return (
        Object.prototype.hasOwnProperty.call(args.content, "one") &&
        Object.prototype.hasOwnProperty.call(args.content, "many")
    );
}
