import Etsy from "common/etsy.context";

const mockFetch: typeof fetch = () =>
    Promise.resolve(new Response(".test {color: red;}", { status: 200 }));

/**
 * Utility to fetch and cache a Constructable Stylesheet for use in Shadow DOM.
 */
export class ShadowStylesheet {
    /**
     * Class behavior should be different in jest tests, since we don't want to
     * include network requests in other teams' suites. ShadowStylesheet tests use it
     * so we can actually test behavior.
     * @internal
     */
    static getEnv = () => (false ? "test" : "prod");

    static getDoesBrowserSupport(): boolean {
        return (
            typeof CSSStyleSheet !== "undefined" &&
            // current version of JSDOM notably has CSSStyleSheet
            // but not the 'replaceSync' method
            "replaceSync" in CSSStyleSheet.prototype
        );
    }

    static stylesheet: CSSStyleSheet | null = null;

    static getStylesheet():
        | CSSStyleSheet
        | null
        | string
        | Promise<CSSStyleSheet | null> {
        if (this.stylesheet) {
            return this.stylesheet;
        }
        if (!this.getDoesBrowserSupport()) {
            return this.getLinkTagString();
        }
        if (this.fetchState === "complete") {
            return this.stylesheet;
        }
        return this.#fetch().then(() => this.stylesheet);
    }

    static fetchState: false | "complete" | "fetching" = false;

    static cssUrl: string | null = null;
    static getCssUrl() {
        return (this.cssUrl ??= Etsy.getString("collage_shadow_dom_css_url"));
    }

    /**
     * Cache the request, so that any components requesting while it's in-flight
     * can await the same promise.
     */
    static request: Promise<void> | null = null;

    static async #fetch(): Promise<void> {
        if (this.request) {
            await this.request;
            return;
        }
        const cssUrl = this.getCssUrl();
        if (
            // We have URL..
            cssUrl &&
            // ...we haven't tried to fetch yet...
            !this.fetchState &&
            // ...and the browser supports Constructable Stylesheets
            // Note that our current version of Jest does not support 'replaceSync',
            // so this will always be false, unless mocked
            this.getDoesBrowserSupport()
        ) {
            this.fetchState = "fetching";
            const fetchRequest = async () => {
                const fetcher = this.getEnv() === "test" ? mockFetch : fetch;
                const response = await fetcher(cssUrl, {
                    mode: "cors",
                });
                const css = await response.text();
                const sheet = new CSSStyleSheet();
                sheet.replaceSync(css);
                this.stylesheet = sheet;
            };

            try {
                this.request = fetchRequest();
                await this.request;
                // eslint-disable-next-line @typescript-eslint/no-unused-vars
            } catch (e) {
                // TODO: log this error?
            } finally {
                this.fetchState = "complete";
                this.request = null;
            }
        }
    }

    static getLinkTagString() {
        const cssUrl = this.getCssUrl();
        return cssUrl
            ? `<link href="${cssUrl}" rel="stylesheet" type="text/css" />`
            : "";
    }

    static createLinkTag() {
        const link = document.createElement("link");
        link.href = this.getCssUrl() || "";
        link.rel = "stylesheet";
        link.type = "text/css";
        return link;
    }

    /** Just used for testing */
    static reset() {
        this.stylesheet = null;
        this.fetchState = false;
        this.cssUrl = null;
        this.request = null;
    }
}
