import type { ClgRemovableChip } from "collage/web-components/components/chip/clg-removable-chip";

interface ClgChipRemoveEventDetail {
    chip: ClgRemovableChip;
}
export class ClgChipRemoveEvent extends Event {
    readonly detail: ClgChipRemoveEventDetail;

    constructor(detail: ClgChipRemoveEventDetail) {
        super("clg-chip-remove", {
            bubbles: true,
            cancelable: true,
            composed: true,
        });
        this.detail = detail;
    }
}
