import { CollageTextFieldElement } from "collage/web-components/internal/CollageTextFieldElement";
import template from "template!collage/clg-text-input";
import type {
    PropertyValues,
    PropertyDeclarations,
} from "collage/web-components/internal/CollageElement";
import {
    togglePasswordVisibilityMsg,
    showInputPickerMsg,
} from "collage/web-components/internal/translations";

export const DATETIME_INPUT_TYPES = [
    "date",
    "datetime-local",
    "time",
    "month",
    "week",
];

/**
 * @tagname clg-text-input
 */
export class ClgTextInput extends CollageTextFieldElement {
    protected static template = template;
    static shadowRootOptions = {
        ...CollageTextFieldElement.shadowRootOptions,
        delegatesFocus: true,
    };

    get #actionIconBtn() {
        return this.shadowRoot?.querySelector<HTMLButtonElement>("#action-button");
    }

    /** Sets the type attribute on the input. */
    declare type:
        | "text"
        | "password"
        | "date"
        | "number"
        | "tel"
        | "time"
        | "datetime-local"
        | "week"
        | "email"
        | "month"
        | "search"
        | "url";

    /** Provides a hint to browsers as to the type of virtual keyboard configuration to use when editing. */
    declare inputMode:
        | "none"
        | "text"
        | "decimal"
        | "numeric"
        | "tel"
        | "search"
        | "email"
        | "url";

    /**
     * Defines the most negative value in the range of permitted values.
     * Valid for types `date`, `month`, `week`, `time`, `datetime-local`, `number`, and `range`
     */
    declare min: number;
    /**
     * Defines the greatest value in the range of permitted values.
     * Valid for types `date`, `month`, `week`, `time`, `datetime-local`, `number`, and `range`
     */
    declare max: number;
    /**
     * A regular expression that the input's value must match in order for the value
     * to pass constraint validation. Valid for types `text`, `tel`, `email`, `url`,
     * `password`, and `search`.
     * @see [MDN](https://developer.mozilla.org/en-US/docs/Web/HTML/Reference/Attributes/pattern)
     */
    declare pattern: string;
    /**
     * Defines the granularity that the value must adhere to. Valid for numeric types like
     * `date`, `month`, `week`, `time`, `datetime-local`, `number` and `range`.
     */
    declare step: number;

    protected declare isPasswordVisible: boolean;

    static override properties: PropertyDeclarations = {
        max: { type: Number, reflect: true },
        min: { type: Number, reflect: true },
        pattern: { type: String, reflect: true },
        step: { type: Number, reflect: true },
        type: { type: String, reflect: true },
        inputMode: { type: String, reflect: true },

        // State
        isPasswordVisible: { type: Boolean, state: true },
    };

    constructor() {
        super();
        this.isPasswordVisible = false;
        this.type = "text";
    }

    protected override willUpdate(changed: PropertyValues) {
        super.willUpdate(changed);

        if (
            changed.has("type") &&
            ![
                "text",
                "password",
                "date",
                "number",
                "tel",
                "time",
                "datetime-local",
                "week",
                "email",
                "month",
                "search",
                "url",
            ].includes(this.type)
        ) {
            // Block any unsupported types
            this.type = "text";
        }

        if (!this.inputMode) {
            switch (this.type) {
                case "email":
                    this.inputMode = "email";
                    break;
                case "number":
                    this.inputMode = "numeric";
                    break;
                case "tel":
                    this.inputMode = "tel";
                    break;
                case "search":
                    this.inputMode = "search";
                    break;
                case "url":
                    this.inputMode = "url";
                    break;
                default:
            }
        }

        if (["password", ...DATETIME_INPUT_TYPES].includes(this.type)) {
            this.withIconAfter = true;
        }
    }

    protected override update(changed: PropertyValues) {
        super.update(changed);

        if (changed.has("isPasswordVisible") && this.type === "password") {
            const toggleButton = this.#actionIconBtn;
            if (toggleButton) {
                if (this.isPasswordVisible) {
                    this.textBox.type = "text";
                    toggleButton.setAttribute("aria-pressed", "true");
                    toggleButton.classList.add(
                        "clg-text-field__action-btn--password-visible"
                    );
                } else {
                    this.textBox.type = "password";
                    toggleButton.setAttribute("aria-pressed", "false");
                    toggleButton.classList.remove(
                        "clg-text-field__action-btn--password-visible"
                    );
                }
            }
        }

        if (changed.has("type")) {
            const btn = this.#actionIconBtn;
            if (btn) {
                if (this.type === "password") {
                    btn.setAttribute("aria-label", togglePasswordVisibilityMsg());
                } else if (DATETIME_INPUT_TYPES.includes(this.type)) {
                    btn.setAttribute("aria-label", showInputPickerMsg());
                    btn.removeAttribute("aria-pressed");
                } else {
                    btn.removeAttribute("aria-label");
                }
            }
        }

        if (changed.has("inputMode")) {
            // Not clear why the binding annotations didn't work, but this works
            this.textBox.inputMode = this.inputMode;
        }
    }

    protected get textBox() {
        // eslint-disable-next-line @typescript-eslint/no-non-null-assertion
        const el = this.shadowRoot!.querySelector<HTMLInputElement>("input")!;
        return el;
    }

    /** For types that support a picker, such as color and date selectors, this will cause the picker to show. */
    public showPicker() {
        this.textBox.showPicker();
    }

    /**
     * When a supported `type` is used, this method will decrease the text field's value by `step`. This is a programmatic
     * change, so `input` and `change` events will not be emitted when this is called.
     */
    public stepDown() {
        this.textBox.stepDown();
    }

    /**
     * When a supported `type` is used, this method will increase the text field's value by `step`. This is a programmatic
     * change, so `input` and `change` events will not be emitted when this is called.
     */
    public stepUp() {
        this.textBox.stepUp();
    }

    #handlePasswordButtonClick = () => {
        this.isPasswordVisible = !this.isPasswordVisible;
        this.textBox.focus();
    };

    /** @internal */
    handleEvent(e: Event) {
        super.handleEvent(e);

        const { intention } = this.findClosestIntention(e);

        switch (intention) {
            case "ACTION_CLICK":
                if (this.type === "password") {
                    this.#handlePasswordButtonClick();
                } else {
                    this.showPicker();
                }
                break;
            default:
        }
    }
}

ClgTextInput.define("clg-text-input");

declare global {
    interface HTMLElementTagNameMap {
        "clg-text-input": ClgTextInput;
    }
}
