import {
    CollageElement,
    type PropertyDeclarations,
    type Validators,
    nonDefaultStringConverter,
    required,
} from "collage/web-components/internal/CollageElement";
import template from "template!collage/clg-signal";

/**
 * @element clg-signal
 *
 * @slot - The signal's text content
 * @slot icon - Icon displayed before the text
 */
export class ClgSignal extends CollageElement {
    protected static override template = template;

    /** How strongly the signal should appear */
    declare variant: "default" | "strong" | "subtle";
    /** Toggles the size modifier to increase the indicator size */
    declare size: "base" | "large";
    /**
     * Selects the correct visual variant
     * @required
     */
    declare color: "neutral" | "highlight" | "promote" | "urgency" | "trust";

    static override properties: PropertyDeclarations = {
        variant: {
            type: String,
            reflect: true,
            converter: nonDefaultStringConverter("default"),
        },
        size: { type: String, reflect: true },
        color: { type: String, reflect: true },
    };

    protected static validators: Validators = {
        variant: required,
        color: required,
    };

    constructor() {
        super();
        this.size = "base";
        this.variant = "default";
    }
}

ClgSignal.define("clg-signal");

declare global {
    interface HTMLElementTagNameMap {
        "clg-signal": ClgSignal;
    }
}
