import {
    CollageElement,
    type PropertyDeclarations,
    type Validators,
    type PropertyValues,
    DEFAULT_SLOT,
} from "collage/web-components/internal/CollageElement";
import template from "template!collage/clg-list";
import { toggleStringAttribute } from "collage/web-components/internal/html";

/**
 * @tagname clg-list
 *
 * @slot title - list title
 * @slot - list content
 */
export class ClgList extends CollageElement {
    protected static override template = template;
    static delegatedEvents = ["slotchange"];
    protected static validators: Validators = {
        [DEFAULT_SLOT]: {
            slot(slot) {
                const assignedElements = slot?.assignedElements() ?? [];
                if (
                    assignedElements.some((el) => el.localName !== "clg-list-item")
                ) {
                    return "clg-list only accepts clg-list-item elements as children";
                }
                return null;
            },
        },
    };

    static override properties: PropertyDeclarations = {
        label: { type: String, reflect: true },
        noDivider: { type: Boolean, reflect: true, attribute: "no-divider" },
        size: { type: String, reflect: true },
    };

    /** Accessible label for the button group */
    declare label?: string;

    /** When true, removes item dividers */
    declare noDivider: boolean;

    /** Sets the size of the list */
    declare size: "small" | "base" | "large";

    constructor() {
        super();
        this.noDivider = false;
        this.size = "base";
    }

    #getItems() {
        return Array.from(this.querySelectorAll("clg-list-item"));
    }

    #syncItemDividers(): void {
        const items = this.#getItems();
        for (const item of items) {
            toggleStringAttribute(
                item,
                "no-divider",
                this.noDivider ? "true" : undefined
            );
        }
    }

    /** Validate the list items are only clg-list-item children */
    #validateListItems(): void {
        if (!(true || false)) return;
        const invalidListItems = [...this.children].filter((el) => {
            if (el.getAttribute("slot") === "title") return false;
            return el.tagName.toLowerCase() !== "clg-list-item";
        });
        if (invalidListItems.length > 0) {
            throw new TypeError(
                `clg-list only accepts clg-list-item children. Found: ${invalidListItems.length}`
            );
        }
    }

    handleEvent(e: Event) {
        const { intention } = this.findClosestIntention(e);
        if (intention === "SLOT_OCCUPIED") {
            this.#validateListItems();
            this.#syncItemDividers();
        }
    }

    connectedCallback() {
        super.connectedCallback();

        this.setAttribute("role", "list");
    }

    override update(changed: PropertyValues) {
        super.update(changed);

        if (changed.has("label")) {
            toggleStringAttribute(this, "aria-label", this.label);
        }

        if (changed.has("noDivider")) {
            this.#syncItemDividers();
        }
    }
}

ClgList.define("clg-list");

declare global {
    interface HTMLElementTagNameMap {
        "clg-list": ClgList;
    }
}
