import {
    CollageElement,
    type PropertyDeclarations,
    type Validators,
    required,
    type PropertyValues,
} from "collage/web-components/internal/CollageElement";
import template from "template!collage/clg-counter-indicator";

/**
 * @tagname clg-counter-indicator
 *
 * A numeric badge used to show counts (e.g. unread, items in cart).
 * Values above 99 are truncated to "99+".
 *
 * @slot - The initial display value, which can be formatted on the server.
 */
export class ClgCounterIndicator extends CollageElement {
    protected static template = template;

    /**
     * Priority of the indicator, which controls its color styling.
     * @required
     */
    declare priority: "neutral" | "highlight" | "important";

    /**
     * Size of the indicator.
     * - "small" matches the base badge size.
     * - "large" matches the larger badge size.
     */
    declare size: "small" | "large";

    /** Whether the indicator has a visible border. */
    declare border: boolean;

    /**
     * The numeric value shown in the badge. Must be a non‑negative integer.
     * Values over 99 are truncated to "99+".
     * @required
     */
    declare value: number;

    /**
     * The formatted value string actually rendered, derived from `value`.
     * For values > 99 this will be "99+".
     */
    protected declare displayValue: string;

    static override properties: PropertyDeclarations = {
        priority: { type: String, reflect: true },
        size: { type: String, reflect: true },
        border: { type: Boolean, reflect: true },
        value: { type: Number },
        displayValue: { state: true },
    };

    protected static validators: Validators<ClgCounterIndicator> = {
        priority: required,
        value: {
            property(this, value, context) {
                if (!value) {
                    return required.call(this, value, context);
                }

                if (
                    typeof value !== "number" ||
                    !Number.isInteger(value) ||
                    value < 0
                ) {
                    return `${context.tagName}: \`value\` must be a non-negative integer.`;
                }

                return null;
            },
        },
    };

    constructor() {
        super();
        this.size = "small";
        this.border = false;
        // value is required; leave it unset until the user sets it.
        this.displayValue = "";
    }

    protected override willUpdate(changed: PropertyValues): void {
        super.willUpdate(changed);

        if (changed.has("value") && typeof this.value === "number") {
            this.displayValue = this.#formatValue(this.value);
        }
    }

    #formatValue(value: number): string {
        if (!Number.isInteger(value) || value < 0) {
            throw new Error(
                "clg-counter-indicator: `value` must be a non-negative integer."
            );
        }
        return value > 99 ? "99+" : String(value);
    }
}

ClgCounterIndicator.define("clg-counter-indicator");

declare global {
    interface HTMLElementTagNameMap {
        "clg-counter-indicator": ClgCounterIndicator;
    }
}
