import {
    CollageElement,
    type PropertyDeclarations,
    type Validators,
    required,
} from "collage/web-components/internal/CollageElement";
import template from "template!collage/clg-navigational-list-item";
import "collage/web-components/components/icon/clg-icon";

/**
 * @tagname clg-navigational-list-item
 *
 * @dependency clg-icon
 *
 * @slot - link content
 */
export class ClgNavigationalListItem extends CollageElement {
    protected static override template = template;
    static shadowRootOptions = {
        ...CollageElement.shadowRootOptions,
        delegatesFocus: true,
    };

    static override properties: PropertyDeclarations = {
        variant: { type: String, reflect: true },
        href: { type: String, reflect: true },
        target: { type: String, reflect: true },
        rel: { type: String, reflect: true },
    };

    protected static validators: Validators = {
        href: required,
    };

    /**
     * Visual style variant - inherits from clg-navigational-list
     * @default "subtle"
     */
    declare variant?: "subtle" | "strong";

    /**
     * URL of a linked resource.
     * @see https://developer.mozilla.org/en-US/docs/Web/API/HTMLAnchorElement/href
     */
    declare href?: string;

    /**
     * Link target
     * _blank	Opens the linked document in a new window or tab
     * _parent Opens the linked document in the parent frame
     * _self Opens the linked document in the same frame as it was clicked (this is default)
     * _top	Opens the linked document in the full body of the window
     * @see https://developer.mozilla.org/en-US/docs/Web/API/HTMLAnchorElement/target
     */
    declare target?: "_blank" | "_parent" | "_self" | "_top";

    /**
     * Defines the relationship between a linked resource and the current document.
     * @see https://developer.mozilla.org/en-US/docs/Web/HTML/Reference/Attributes/rel
     */
    declare rel?: string;

    connectedCallback() {
        super.connectedCallback();
        this.setAttribute("role", "link");
    }
}

ClgNavigationalListItem.define("clg-navigational-list-item");

declare global {
    interface HTMLElementTagNameMap {
        "clg-navigational-list-item": ClgNavigationalListItem;
    }
}
