import type { JSX, FunctionComponentElement } from "react";
import transform, { type Transformer } from "translator/mini-mustache/transform";
import type { TTree } from "translator/mini-mustache/types";
import Block from "translator/preact/Block";
import Variable from "translator/preact/Variable";
import type { TemplateArgs } from "translator/preact/types";

interface ElementContext {
    args: TemplateArgs;
    nextKey: () => string;
}

const toElementTransformer: Transformer<
    JSX.Element,
    FunctionComponentElement<typeof Block>,
    FunctionComponentElement<typeof Variable>,
    ElementContext
> = {
    visitTree: (children, _context) => <>{children}</>,
    visitBlock: (variable, children, context) => (
        <Block
            key={context.nextKey()}
            tagKey={variable}
            args={context.args}
            // eslint-disable-next-line react/no-children-prop
            children={children}
        />
    ),
    visitVariable: (variable, context) => (
        <Variable key={context.nextKey()} tagKey={variable} args={context.args} />
    ),
};

export default function renderToPreact(tree: TTree, args: TemplateArgs) {
    let key = 1;
    // Transform from a parse tree into a Preact element tree, passing along the args to every
    // Block and Variable element via the transformer.
    return transform(tree, toElementTransformer, {
        args,
        nextKey: () => (key++).toString(),
    });
}
