import type { ClgToastGroup } from "collage/web-components/components/toast/clg-toast-group";
import type { ClgToast } from "collage/web-components/components/toast/clg-toast";
import type { ClgCloseEvent } from "collage/web-components/events/open-close";

// Define/register the elements
import "collage/web-components/components/toast/clg-toast-group";
import "collage/web-components/components/toast/clg-toast";

function createTransitionGroupIfNone() {
    let transitionGroup = document.querySelector<ClgToastGroup>(
        "#clg-toast-transition-group"
    );
    if (!transitionGroup) {
        transitionGroup = document.createElement("clg-toast-group");
        transitionGroup.id = "clg-toast-transition-group";
        document.body.appendChild(transitionGroup);
    }
    return transitionGroup;
}

interface ToastOptions
    extends Pick<ClgToast, "color">,
        Partial<Pick<ClgToast, "duration" | "icon">> {
    /** Called when the toast is dismissed, either by the timer or manually be the user. */
    onClose?: (event: ClgCloseEvent) => void;
}

/**
 * Utilities for queuing a toast notification, centrally managed by Collage.
 */
export const toast = {
    /** Queues a toast notification. Returns a reference to the created toast. */
    async create(text: string, { onClose, ...options }: ToastOptions) {
        const group = createTransitionGroupIfNone();

        const item = document.createElement("clg-toast");
        Object.assign(item, options);
        item.textContent = text;
        if (onClose) {
            item.addEventListener("clg-close", onClose);
        }
        await group.queue(item);
        return item;
    },
    /**
     * Creates a toast notification using an existing `<clg-toast>` element. Useful if you want to create your own
     * toast items declaratively. Returns a reference to the cloned toast item.
     */
    async createFromTemplate(
        toastTemplate: HTMLTemplateElement,
        options?: Pick<ToastOptions, "onClose">
    ): Promise<ClgToast> {
        if (toastTemplate.localName !== "template") {
            throw new Error("not a template");
        }

        // eslint-disable-next-line @typescript-eslint/consistent-type-assertions
        const clone = toastTemplate.content.cloneNode(true) as DocumentFragment;
        const toastEl = clone.querySelector<ClgToast>("clg-toast");
        if (!toastEl) {
            throw new Error("wrong element");
        }

        if (options?.onClose) {
            toastEl.addEventListener("clg-close", options.onClose);
        }

        const group = createTransitionGroupIfNone();
        await group.queue(toastEl);
        return toastEl;
    },
};
