/**
 * Composed-tree offset parent resolution for Floating UI, adapted from the
 * `composed-offset-position` package (MIT), without adding an npm dependency.
 *
 * @see https://www.npmjs.com/package/composed-offset-position
 */

/** Walk flat tree (slots + shadow) toward document. */
function flatTreeParent(node: Node | null): Node | null {
    if (!node) {
        return null;
    }
    if (node instanceof Element && node.assignedSlot) {
        return node.assignedSlot;
    }
    if (node.parentNode instanceof ShadowRoot) {
        return node.parentNode.host;
    }
    return node.parentNode;
}

/**
 * Whether computed style establishes a containing block for absolute descendants
 * (subset of CSS containing block rules; aligned with Floating UI utils).
 */
function isContainingBlock(style: CSSStyleDeclaration): boolean {
    const willChangeTokens = style.willChange.split(",").map((t) => t.trim());
    const backdrop =
        style.backdropFilter !== "none" &&
        style.backdropFilter !== undefined &&
        style.backdropFilter.length > 0;
    const webkitBackdrop = style.getPropertyValue("-webkit-backdrop-filter");
    const webkitBackdropActive =
        webkitBackdrop !== "" &&
        webkitBackdrop !== "none" &&
        webkitBackdrop.length > 0;

    return (
        style.transform !== "none" ||
        style.perspective !== "none" ||
        (style.filter !== "none" &&
            style.filter !== undefined &&
            style.filter.length > 0) ||
        backdrop ||
        webkitBackdropActive ||
        style.contain === "paint" ||
        willChangeTokens.includes("transform") ||
        willChangeTokens.includes("perspective") ||
        willChangeTokens.includes("filter") ||
        willChangeTokens.includes("backdrop-filter")
    );
}

/**
 * Polyfill for `offsetParent` that follows the composed tree (shadow + slots).
 * Use as the second argument to Floating UI's `platform.getOffsetParent`.
 * This is a npm dependency that we are not importing, so we are including it here.
 * @see https://www.npmjs.com/package/composed-offset-position
 */
export function composedOffsetParentPolyfill(element: Element): Element | null {
    for (
        let ancestor: Node | null = element;
        ancestor;
        ancestor = flatTreeParent(ancestor)
    ) {
        if (!(ancestor instanceof Element)) {
            continue;
        }
        if (getComputedStyle(ancestor).display === "none") {
            return null;
        }
    }

    for (
        let ancestor: Node | null = flatTreeParent(element);
        ancestor;
        ancestor = flatTreeParent(ancestor)
    ) {
        if (!(ancestor instanceof Element)) {
            continue;
        }
        const style = getComputedStyle(ancestor);
        if (style.display === "contents") {
            continue;
        }
        if (style.position !== "static" || isContainingBlock(style)) {
            return ancestor;
        }
        if (ancestor.tagName === "BODY") {
            return ancestor;
        }
    }
    return null;
}
