import {
    CollageElement,
    type PropertyDeclarations,
    type Validators,
    required,
    type PropertyValues,
} from "collage/web-components/internal/CollageElement";
import template from "template!collage/clg-button";
import { onDOMReady } from "es6/utils/load-listeners";
import { AnchorOrButtonMixin } from "collage/web-components/mixins/AnchorOrButtonMixin";
import "collage/web-components/components/loading-spinner/clg-loading-spinner";
import { forwardClicksInTests } from "collage/web-components/internal/forward-clicks-in-tests";
import { LoadingButtonController } from "collage/web-components/reactive-controllers/LoadingButtonController";

/**
 * @tagname clg-button
 *
 * @dependency clg-loading-spinner
 *
 * @slot - button content
 * @slot submit-input - An `input[type="submit"]` to support form submission without JS. Must be used with `withSubmit`.
 */
export class ClgButton extends AnchorOrButtonMixin(CollageElement) {
    protected static override template = template;
    protected static validators: Validators = {
        variant: required,
    };
    static formAssociated = true;
    static shadowRootOptions = {
        ...CollageElement.shadowRootOptions,
        delegatesFocus: true,
    };

    static override properties: PropertyDeclarations = {
        variant: { type: String, reflect: true },
        name: { type: String },
        value: { type: String },
        size: { type: String, reflect: true },
        loading: { type: Boolean, reflect: true },
        backgroundType: {
            type: String,
            reflect: true,
            attribute: "background-type",
        },
        withSubmit: { type: Boolean, reflect: true, attribute: "with-submit" },
        withrefresh: { type: Boolean, reflect: true },
        // All of these properties are reflecting real properties + attribute counterparts
        /* eslint-disable etsy-rules/lit-attribute-names */
        formAction: { attribute: "formaction" },
        formEnctype: { attribute: "formenctype" },
        formNoValidate: { attribute: "formnovalidate", type: Boolean },
        formTarget: { attribute: "formtarget" },
        formMethod: { attribute: "formmethod" },
        /* eslint-enable etsy-rules/lit-attribute-names */
    };

    /**
     * Visual look of the button
     * @required
     */
    declare variant: "primary" | "secondary" | "tertiary";
    /** The name of the button */
    declare name: string;
    /** The value of the button */
    declare value: string | null;
    /** Size of the button */
    declare size: "base" | "small";
    /** If true, will display a loading spinner */
    declare loading: boolean;
    /** The style of background the button is on */
    declare backgroundType: "dynamic" | "light" | "dark";
    /** Temporary prop for testing refresh styles with clg-button */
    protected declare withrefresh: boolean;
    /** Used to override the form owner's `action` attribute. */
    declare formAction: string;
    /** Used to override the form owner's `enctype` attribute.  */
    declare formEnctype:
        | "application/x-www-form-urlencoded"
        | "multipart/form-data"
        | "text/plain";
    /** Used to override the form owner's `method` attribute.  */
    declare formMethod: "post" | "get";
    /** Used to override the form owner's `novalidate` attribute. */
    declare formNoValidate: boolean;
    /** Used to override the form owner's `target` attribute. */
    declare formTarget: "_self" | "_blank" | "_parent" | "_top" | string;

    // On `withSubmit` and `submit-input` slot:
    //
    // <button> elements in the shadow DOM cannot implicitly submit forms
    // in a different DOM (shadow or light). We can work around this with JS
    // to imperatively submit the form, but that doesn't work in no JS environments
    //
    // In cases where form submission without JS is critical, you can use this
    // property and slot to slot a input[type="submit"] in the light DOM to make
    // button clicks submit the form (and ensure the markup is accessible/semantic)
    // When JS runs, we hide the slotted input and use JS for form submissions like normal

    /**
     * Whether or not the 'submit-input' slot is occupied.
     * Use alongside the slot to support form submisssion without JS.
     * Usually unnecessary, unless for the add to cart button
     */
    declare withSubmit?: boolean;

    #internals = this.attachInternals();

    static delegatedEvents = ["pointerup", "click"];

    constructor() {
        super();
        this.size = "base";
        this.loading = false;
        this.backgroundType = "dynamic";
        this.withrefresh = false;
        this.disabled = false;

        new LoadingButtonController(this, () => this.#button);
        forwardClicksInTests(this, () => this.#button);
    }

    get #button() {
        return this.shadowRoot?.querySelector<HTMLButtonElement>(
            "[data-button-root]"
        );
    }
    get _button() {
        return this.#button;
    }

    override connectedCallback() {
        super.connectedCallback();
        // Dark mode (only for checkout and sign in flows)
        // If we are in dark mode, add attribute backgroundType="dark" for styling
        if (document.body.getAttribute("data-clg-mode") === "dark") {
            this.backgroundType = "dark";
            this.withrefresh = false;
        }
    }

    override firstUpdated(changed: PropertyValues) {
        super.firstUpdated(changed);

        // If using withSubmit and submit-input for form submission without JS,
        // revert to our regular <button> element.
        // IMPORTANT: without onDOMReady, this causes a flash of empty space
        // in Safari (as of iOS/MacOS 26.2)
        onDOMReady(() => {
            const oldRoot = this.#button;
            if (
                this.withSubmit &&
                oldRoot &&
                oldRoot.tagName.toLowerCase() !== "button"
            ) {
                const newRoot = document.createElement("button");
                for (const { name, value } of Array.from(oldRoot.attributes)) {
                    newRoot.setAttribute(name, value);
                }
                while (oldRoot.firstChild) {
                    newRoot.appendChild(oldRoot.firstChild);
                }
                oldRoot.replaceWith(newRoot);
                newRoot.querySelector("#content")?.removeAttribute("aria-hidden");
                this.querySelector('input[slot="submit-input"]')?.remove();
                // Using in CSS to hide the slot, just in case
                this.setAttribute("hydrated", "");
            }
        });
    }

    /** @internal */
    handleEvent(e: Event) {
        const { intention } = this.findClosestIntention(e);
        if (intention === "RELEASE") {
            // A JS workaround to get a separate "release" animation from "unhover"
            this.#button?.toggleAttribute("data-released", true);
            setTimeout(() => {
                this.#button?.toggleAttribute("data-released", false);
            }, 200);
        }
        if (intention === "CLICK") {
            this.#handleClick(e);
        }
    }

    #handleClick = (event: Event) => {
        // Prevent disabled and loading buttons from being clicked
        if (this.disabled || this.loading) {
            event.preventDefault();
            event.stopImmediatePropagation();
            return;
        }

        const form = this.#internals.form;

        if (!form || this.href) return;

        const button = document.createElement("button");

        for (const attribute of this.attributes) {
            if (attribute.name === "style") {
                // Skip style attributes as they *shouldn't* be necessary
                continue;
            }
            button.setAttribute(attribute.name, attribute.value);
        }

        button.type = this.type || "button";
        button.style.position = "absolute";
        button.style.width = "0";
        button.style.height = "0";
        button.style.clipPath = "inset(50%)";
        button.style.overflow = "hidden";
        button.style.whiteSpace = "nowrap";
        if (this.name) {
            button.name = this.name;
        }
        button.value = this.value || "";

        form.append(button);
        button.click();
        button.remove();
    };

    public focus(opts?: FocusOptions) {
        if (this.#button) {
            this.#button.focus(opts);
        } else {
            this.updateComplete.then(() => {
                this.#button?.focus(opts);
            });
        }
    }
    public blur() {
        if (this.#button) {
            this.#button.blur();
        } else {
            this.updateComplete.then(() => {
                this.#button?.blur();
            });
        }
    }
    public click() {
        if (this.#button) {
            this.#button.click();
        } else {
            this.updateComplete.then(() => {
                this.#button?.click();
            });
        }
    }
}

ClgButton.define("clg-button");

declare global {
    interface HTMLElementTagNameMap {
        "clg-button": ClgButton;
    }
}
