import {
    CollageElement,
    type PropertyDeclarations,
} from "collage/web-components/internal/CollageElement";
import template from "template!collage/clg-banner-base";
import { ClgCloseEvent } from "collage/web-components/events/open-close";
import "collage/web-components/components/icon/clg-icon";
import "collage/web-components/components/icon-button/clg-icon-button";

/**
 * @tagname clg-banner-base
 *
 * @dependency clg-icon-button
 * @dependency clg-icon
 *
 * @slot - banner message
 * @slot icon - icon
 * @slot title - banner title
 *
 * @fires {ClgCloseEvent} clg-close - Event fired when the close button is clicked.
 */
export class ClgBannerBase extends CollageElement {
    protected static template = template;

    /**
     * Buttons variants for different call to action use cases.
     */
    declare buttons?: "buttonGroup" | "inlineButton" | "dismissOnly" | "none";
    /**
     * Whether the banner is open or not (for use with open-close events)
     */
    declare open?: boolean;

    declare subtitle?: boolean;

    static override properties: PropertyDeclarations = {
        buttons: { type: String, reflect: true },
        open: { type: Boolean, reflect: true },
        subtitle: { type: Boolean, reflect: true },
    };

    static delegatedEvents = ["click", "slotchange"];

    constructor() {
        super();
        this.buttons = "none";
        this.open = false;
        this.subtitle = false;
    }

    #dismiss() {
        const defaultPrevented = !this.dispatchEvent(
            new ClgCloseEvent({ origin: "user" }, { cancelable: true })
        );
        if (!defaultPrevented) {
            this.open = false;
        }
    }

    handleEvent(e: Event) {
        const { intention, target } = this.findClosestIntention(e);
        if (intention === "DISMISS") {
            this.#dismiss();
        } else if (intention === "SLOT_OCCUPIED") {
            // eslint-disable-next-line @typescript-eslint/consistent-type-assertions
            const slot = target as HTMLSlotElement;
            // Check if there is content in the child subtitle slot (subtitle slot of outer banner)
            const slotOccupied = slot.assignedNodes({ flatten: true }).length > 0;
            this.subtitle = slotOccupied;
        }
    }
}

ClgBannerBase.define("clg-banner-base");

declare global {
    interface HTMLElementTagNameMap {
        "clg-banner-base": ClgBannerBase;
    }
}
