import { CollageTextFieldElement } from "collage/web-components/internal/CollageTextFieldElement";
import template from "template!collage/clg-textarea";
import type { PropertyDeclarations } from "@lit/reactive-element";

/**
 * @tagname clg-textarea
 */
export class ClgTextarea extends CollageTextFieldElement {
    protected static template = template;

    /**
     * The minimum number of visible rows of text. If the length of the text
     * exceeds this number, the textarea's height will grow to accommodate.
     */
    declare rows?: number;

    /**
     * Sets how the textarea can be resized. If "auto", the height of the textarea
     * will dynamically adjust to fit the content. If "vertical", the user will
     * be presented a drag handle to adjust the height manually.
     */
    declare resize: "auto" | "none" | "vertical";

    static override properties: PropertyDeclarations = {
        rows: { type: Number },
        resize: { type: String, reflect: true },
    };

    constructor() {
        super();
        this.rows = 3;
        this.resize = "none";
    }

    protected get textBox() {
        // eslint-disable-next-line @typescript-eslint/no-non-null-assertion
        const el = this.shadowRoot!.querySelector("textarea")!;
        return el;
    }
}

ClgTextarea.define("clg-textarea");

declare global {
    interface HTMLElementTagNameMap {
        "clg-textarea": ClgTextarea;
    }
}
