/** Emitted when the content of the target node has mutated. */
export class ClgContentChangedEvent extends Event {
    readonly detail: ClgContentChangedEventDetail;

    constructor(detail: ClgContentChangedEventDetail) {
        super("clg-content-changed", {
            bubbles: true,
            cancelable: false,
            composed: true,
        });
        this.detail = detail;
    }
}

interface ClgContentChangedEventDetail {
    mutations: MutationRecord[];
}

declare global {
    interface GlobalEventHandlersEventMap {
        "clg-content-changed": ClgContentChangedEvent;
    }
}
