import {
    CollageElement,
    type PropertyDeclarations,
    type Validators,
    required,
    type PropertyValues,
} from "collage/web-components/internal/CollageElement";
import { removeAriaLabelMsg } from "collage/web-components/internal/translations";
import template from "template!collage/clg-removable-chip";
import "collage/web-components/components/icon/clg-icon";

/**
 * @tagname clg-removable-chip
 *
 * @dependency clg-icon
 *
 * @slot icon - optionally appears before the label
 */
export class ClgRemovableChip extends CollageElement {
    protected static override template = template;

    static override properties: PropertyDeclarations = {
        label: { type: String, reflect: true },
        size: { type: String, reflect: true },
        disabled: { type: Boolean, reflect: true },
    };

    protected static validators: Validators = {
        label: required,
    };

    /**
     * The text content of the removable chip
     * @required
     */
    declare label: string;
    /** Toggles the size modifier to increase the chip size */
    declare size: "base" | "large";
    /** Whether or not the chip is interactive */
    declare disabled: boolean;

    get #button() {
        return this.shadowRoot?.querySelector<HTMLButtonElement>(
            "button.clg-removable-chip"
        );
    }

    override update(changed: PropertyValues) {
        super.update(changed);
        if (changed.has("label")) {
            this.#button?.setAttribute(
                "aria-label",
                removeAriaLabelMsg({ label: this.label })
            );
        }
    }

    constructor() {
        super();
        this.size = "base";
        this.disabled = false;
    }
}

ClgRemovableChip.define("clg-removable-chip");

declare global {
    interface HTMLElementTagNameMap {
        "clg-removable-chip": ClgRemovableChip;
    }
}
