import {
    CollageElement,
    type PropertyDeclarations,
    type Validators,
    required,
} from "collage/web-components/internal/CollageElement";

/**
 * @tagname clg-select-optgroup
 */
export class ClgSelectOptGroup extends CollageElement {
    /**
     * The name of the group of options.
     * @required
     */
    declare label: string;
    /** If true, none of the items in this option group is selectable */
    declare disabled: boolean;

    static properties: PropertyDeclarations = {
        label: { reflect: true },
        disabled: { type: Boolean, reflect: true },
    };

    static validators: Validators = {
        label: required,
    };

    constructor() {
        super();
        this.disabled = false;
    }
}

ClgSelectOptGroup.define("clg-select-optgroup");
declare global {
    interface HTMLElementTagNameMap {
        "clg-select-optgroup": ClgSelectOptGroup;
    }
}
