import {
    CollageElement,
    type PropertyDeclarations,
    type PropertyValues,
} from "collage/web-components/internal/CollageElement";
import template from "template!collage/clg-favorite-button";
import "collage/web-components/components/icon/clg-icon";

/**
 * @tagname clg-favorite-button
 * @summary A button to favorite an item, represented by a heart icon.
 * @dependency clg-icon
 */
export class ClgFavoriteButton extends CollageElement {
    protected static override template = template;
    static shadowRootOptions = {
        ...CollageElement.shadowRootOptions,
        delegatesFocus: true,
    };
    static override properties: PropertyDeclarations = {
        selected: { type: Boolean, reflect: true },
        size: { type: String, reflect: true },
        backgroundType: {
            type: String,
            reflect: true,
            attribute: "background-type",
        },
    };

    /** Visual look of the button on different surfaces */
    declare backgroundType: "dynamic" | "light" | "dark";

    /** If true, will display a filled favorite heart */
    declare selected: boolean;

    /** Visual size of the button  */
    declare size: "base" | "small";

    constructor() {
        super();
        this.backgroundType = "dynamic";
        this.selected = false;
        this.size = "base";
    }

    update(changed: PropertyValues) {
        super.update(changed);

        const icon = this.shadowRoot?.querySelector("clg-icon");
        if (icon) {
            icon.name = this.selected ? "heart_fill" : "heart";
        }

        const btn = this.shadowRoot?.querySelector("button");
        if (btn) {
            btn.setAttribute("aria-pressed", String(this.selected));
        }
    }
}

ClgFavoriteButton.define("clg-favorite-button");

declare global {
    interface HTMLElementTagNameMap {
        "clg-favorite-button": ClgFavoriteButton;
    }
}
