import {
    CollageElement,
    type PropertyDeclarations,
    type PropertyValues,
} from "collage/web-components/internal/CollageElement";
import template from "template!collage/clg-checkbox-square";
import "collage/web-components/components/icon/clg-icon";

/**
 * @tagname clg-checkbox-square
 *
 * @dependency clg-icon
 *
 * @summary A checkbox square display element.
 */
export class ClgCheckboxSquare extends CollageElement {
    protected static template = template;

    static properties: PropertyDeclarations = {
        checked: { type: Boolean, reflect: true },
        size: { type: String, reflect: true },
        invalid: { type: Boolean, reflect: true },
        focused: { type: Boolean, reflect: true },
    };

    /** Whether the radio is selected */
    declare checked: boolean;

    /** The size of the checkbox square */
    declare size: "small" | "base";

    /** Whether the checkbox square is invalid */
    declare invalid: boolean;

    /** Whether the checkbox square is disabled */
    declare disabled: boolean;

    /** Whether the checkbox square should display the focus state */
    declare focused: boolean;

    constructor() {
        super();
        this.checked = false;
        this.size = "base";
        this.invalid = false;
        this.disabled = false;
        this.focused = false;
    }

    update(changed: PropertyValues) {
        super.update(changed);

        if (changed.has("checked") && changed.get("checked") !== undefined) {
            // Only add the `animation` CSS property if the checked value changes
            // after the first render (the changed value is always undefined on first render)
            this.toggleAttribute("rendered", true);
        }
    }
}

ClgCheckboxSquare.define("clg-checkbox-square");

declare global {
    interface HTMLElementTagNameMap {
        "clg-checkbox-square": ClgCheckboxSquare;
    }
}
