import {
    CollageElement,
    type PropertyDeclarations,
    type Validators,
    type PropertyValues,
    required,
} from "collage/web-components/internal/CollageElement";
import template from "template!collage/clg-profile-avatar";
import "collage/web-components/components/icon/clg-icon";
import "collage/web-components/components/shape/clg-shape";
import "collage/web-components/components/logo/clg-logo";

/**
 * @tagname clg-profile-avatar
 *
 * @dependency clg-shape
 * @dependency clg-icon
 * @dependency clg-logo
 *
 * @slot - avatar content (image or initials)
 * @slot badge - the badge appearing on bottom right corner (e.g., etsy admin or star seller)
 */
export class ClgProfileAvatar extends CollageElement {
    protected static template = template;

    /**
     * Color variant for the profile avatar.
     * @required
     */
    declare color: "red" | "yellow" | "green" | "blue" | "purple" | "teal";

    /**
     * Shape variant for the profile avatar.
     * @required
     */
    declare shape: "1" | "2" | "3" | "4" | "5" | "6" | "7" | "8";

    /**
     * Default initial for the avatar (used when no image is provided in the slot)
     * @required
     */
    declare initial: string;

    /**
     * Size variant for the profile avatar.
     */
    declare size: "smallest" | "smaller" | "base" | "larger" | "largest";

    /**
     * Badge variant for the profile avatar.
     */
    declare badge: "etsy-admin" | "star-seller" | false;

    /**
     * Whether the profile avatar has a border.
     */
    declare border: boolean;

    /**
     * Whether the profile avatar has an image.
     * For SSR support with slots, sets whether the default slot is occupied with an image
     */
    declare withImage: boolean;

    static override properties: PropertyDeclarations = {
        color: { type: String, reflect: true },
        shape: { type: String, reflect: true },
        initial: { type: String, reflect: true },
        size: { type: String, reflect: true },
        badge: { type: String, reflect: true },
        border: { type: Boolean, reflect: true },
        withImage: { type: Boolean, reflect: true, attribute: "with-image" },
    };

    protected static validators: Validators = {
        color: required,
        shape: required,
        initial: required,
    };

    static delegatedEvents = ["slotchange"];

    constructor() {
        super();
        this.size = "base";
        this.badge = false;
        this.border = false;
        this.withImage = false;
    }

    get #shape() {
        return this.shadowRoot?.querySelector("clg-shape");
    }

    override update(changed: PropertyValues) {
        super.update(changed);
        if (changed.has("shape")) {
            this.#shape?.setAttribute("name", `special_shape_0${this.shape}`);
        }
    }

    /** @internal */
    handleEvent(e: Event) {
        const { intention } = this.findClosestIntention(e);
        if (intention === "SLOT_OCCUPIED") {
            this.withImage = this.hasSlotContent("[default]");
        }
    }
}

ClgProfileAvatar.define("clg-profile-avatar");

declare global {
    interface HTMLElementTagNameMap {
        "clg-profile-avatar": ClgProfileAvatar;
    }
}
